// ═══════════════════════════════════════════════════════════════════
// FFMPEG CONFIGURATION
// ═══════════════════════════════════════════════════════════════════

let ffmpeg = null;
let ffprobePath = null;

// Dynamic import for fluent-ffmpeg (ESM compatible)
async function initFFmpeg() {
  if (ffmpeg) return ffmpeg;
  try {
    const fluentFFmpeg = await import('fluent-ffmpeg');
    ffmpeg = fluentFFmpeg.default || fluentFFmpeg;

    // Try to get ffprobe path from installer
    try {
      const ffprobeInstaller = await import('@ffprobe-installer/ffprobe');
      ffprobePath = ffprobeInstaller.path;
      ffmpeg.setFfprobePath(ffprobePath);
    } catch {
      // Use system ffprobe
      ffprobePath = '/usr/bin/ffprobe';
    }

    return ffmpeg;
  } catch (error) {
    console.error('[FFmpeg] Failed to load:', error.message);
    return null;
  }
}

// ═══════════════════════════════════════════════════════════════════
// S3 CONFIGURATION
// ═══════════════════════════════════════════════════════════════════

const S3_BUCKET = process.env.AWS_S3_BUCKET || process.env.S3_BUCKET || 'mumtaz-ai-bucket';
const S3_REGION = process.env.AWS_REGION || 'ap-southeast-1';

const s3Client = new S3Client({
  region: S3_REGION,
  credentials: {
    accessKeyId: process.env.AWS_ACCESS_KEY_ID,
    secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY,
  },
});

/**
 * Upload file to S3
 */
async function uploadToS3(key, content, mimeType) {
  try {
    const buffer =
      typeof content === 'string' ? Buffer.from(content, 'utf-8') : content;

    await s3Client.send(
      new PutObjectCommand({
        Bucket: S3_BUCKET,
        Key: key,
        Body: buffer,
        ContentType: mimeType,
      })
    );

    const url = `https://${S3_BUCKET}.s3.${S3_REGION}.amazonaws.com/${key}`;
    console.log(`[S3] Uploaded: ${key} (${buffer.length} bytes)`);

    return { success: true, url, key };
  } catch (error) {
    console.error('[S3] Upload error:', error);
    return { success: false, error: error.message };
  }
}

/**
 * Download file from S3
 */
async function downloadFromS3(key) {
  try {
    const response = await s3Client.send(
      new GetObjectCommand({
        Bucket: S3_BUCKET,
        Key: key,
      })
    );

    const chunks = [];
    for await (const chunk of response.Body) {
      chunks.push(chunk);
    }
    const buffer = Buffer.concat(chunks);

    return {
      success: true,
      content: buffer,
      mimeType: response.ContentType,
      size: response.ContentLength,
    };
  } catch (error) {
    console.error('[S3] Download error:', error);
    return { success: false, error: error.message };
  }
}

/**
 * Delete file from S3
 */
async function deleteFromS3(key) {
  try {
    await s3Client.send(
      new DeleteObjectCommand({
        Bucket: S3_BUCKET,
        Key: key,
      })
    );
    console.log(`[S3] Deleted: ${key}`);
    return { success: true };
  } catch (error) {
    console.error('[S3] Delete error:', error);
    return { success: false, error: error.message };
  }
}

