// ═══════════════════════════════════════════════════════════════════
// FORMAT CONVERTERS
// ═══════════════════════════════════════════════════════════════════

/**
 * Convert Anthropic tool format to OpenAI tool format
 * Anthropic: { name, description, input_schema }
 * OpenAI:    { type: "function", function: { name, description, parameters } }
 */
export function getToolsForOpenAI(tools) {
  return tools.map((t) => ({
    type: 'function',
    function: {
      name: t.name,
      description: t.description,
      parameters: t.input_schema,
    },
  }));
}

// ═══════════════════════════════════════════════════════════════════
// TOOL EXECUTION — Direct call (no HTTP self-loop)
// ═══════════════════════════════════════════════════════════════════

/**
 * Execute a tool call directly via executeTool().
 * Previously this made an HTTP POST to itself (/api/agents/tools/execute)
 * which then called executeTool() — an unnecessary network round-trip.
 * Now calls executeTool() directly in the same process.
 * Includes permission check via agent-intelligence-service.js
 */
export async function executeToolCall(toolName, toolInput, userId, agentId) {
  try {
    // ⚡ ENFORCED MODE CHECK — block tools not allowed in current mode
    try {
      const { checkToolPermission } = await import('./agent-intelligence-service.js');
      const permission = await checkToolPermission(toolName, userId);
      if (!permission.allowed) {
        console.log(`[tool-exec] BLOCKED: ${toolName} — ${permission.reason}`);
        return { success: false, error: permission.reason };
      }
    } catch (permErr) {
      // If permission check fails, allow execution (fail-open for resilience)
      console.warn('[tool-exec] Permission check failed, allowing:', permErr.message);
    }

    console.log(`[tool-exec] Executing directly: ${toolName}`);
    const params = { ...toolInput, userId, agentId };
    const result = await executeTool(toolName, params);

    // Normalize result shape (executeTool returns the raw result)
    const succeeded = result?.success !== false;
    if (succeeded) {
      console.log(`[tool-exec] ${toolName} succeeded`);
      return { success: true, data: result };
    }

    return {
      success: false,
      error: result?.error || 'Tool execution failed',
    };
  } catch (error) {
    console.error(`[tool-exec] ${toolName} failed:`, error);
    return { success: false, error: error?.message || String(error) };
  }
}

