/**
 * Web Search using SerpAPI (Google results) with DuckDuckGo fallback
 */
export async function webSearch(query, numResults = 5) {
  const serpApiKey = process.env.SERPAPI_API_KEY;

  // Try SerpAPI first (real Google results)
  if (serpApiKey) {
    try {
      console.log(`[web_search] Trying SerpAPI for "${query}" (key starts: ${serpApiKey.substring(0, 8)}...)`);
      const encodedQuery = encodeURIComponent(query);
      const response = await fetch(
        `https://serpapi.com/search.json?q=${encodedQuery}&api_key=${serpApiKey}&num=${numResults}&engine=google`
      );

      if (response.ok) {
        const data = await response.json();
        const results = [];

        // Answer box / featured snippet
        if (data.answer_box) {
          const ab = data.answer_box;
          results.push({
            title: ab.title || 'Answer',
            snippet: ab.answer || ab.snippet || ab.result || '',
            url: ab.link || '',
            source: 'Google (Featured)',
          });
        }

        // Knowledge graph
        if (data.knowledge_graph) {
          const kg = data.knowledge_graph;
          results.push({
            title: kg.title || 'Knowledge',
            snippet: kg.description || kg.snippet || '',
            url: kg.source?.link || kg.website || '',
            source: kg.source?.name || 'Google Knowledge Graph',
          });
        }

        // Organic results — the main search results
        if (data.organic_results && data.organic_results.length > 0) {
          for (const r of data.organic_results.slice(0, numResults)) {
            results.push({
              title: r.title || '',
              snippet: r.snippet || '',
              url: r.link || '',
              source: r.source || r.displayed_link || 'Google',
              date: r.date || undefined,
            });
          }
        }

        // Related questions (People Also Ask)
        if (data.related_questions && data.related_questions.length > 0 && results.length < numResults) {
          for (const rq of data.related_questions.slice(0, 2)) {
            results.push({
              title: rq.question || '',
              snippet: rq.snippet || '',
              url: rq.link || '',
              source: 'People Also Ask',
            });
          }
        }

        if (results.length > 0) {
          console.log(`[web_search] SerpAPI returned ${results.length} results for "${query}"`);
          return {
            success: true,
            query,
            results: results.slice(0, numResults),
            totalResults: results.length,
            engine: 'google',
          };
        } else {
          console.warn(`[web_search] SerpAPI response OK but 0 results extracted for "${query}". Had: answer_box=${!!data.answer_box}, knowledge_graph=${!!data.knowledge_graph}, organic_results=${data.organic_results?.length || 0}`);
        }
      } else {
        const errorBody = await response.text().catch(() => '');
        console.warn(`[web_search] SerpAPI returned ${response.status}, falling back to DuckDuckGo. Body: ${errorBody.substring(0, 200)}`);
      }
    } catch (serpError) {
      console.warn('[web_search] SerpAPI error, falling back to DuckDuckGo:', serpError.message);
    }
  }

  // Fallback: DuckDuckGo Instant Answer API
  try {
    const encodedQuery = encodeURIComponent(query);
    const response = await fetch(
      `https://api.duckduckgo.com/?q=${encodedQuery}&format=json&no_html=1&skip_disambig=1`
    );

    if (!response.ok) {
      throw new Error(`Search failed: ${response.status}`);
    }

    const data = await response.json();
    const results = [];

    // Abstract (main answer)
    if (data.Abstract) {
      results.push({
        title: data.Heading || 'Summary',
        snippet: data.Abstract,
        url: data.AbstractURL || '',
        source: data.AbstractSource || 'DuckDuckGo',
      });
    }

    // Related topics
    if (data.RelatedTopics && data.RelatedTopics.length > 0) {
      for (const topic of data.RelatedTopics.slice(
        0,
        numResults - results.length
      )) {
        if (topic.Text) {
          results.push({
            title: topic.Text.split(' - ')[0] || 'Related',
            snippet: topic.Text,
            url: topic.FirstURL || '',
            source: 'DuckDuckGo',
          });
        }
      }
    }

    if (results.length === 0) {
      return {
        success: true,
        query,
        results: [],
        message: `No instant results found for "${query}". The agent should try rephrasing or provide general knowledge.`,
        engine: 'duckduckgo',
      };
    }

    return {
      success: true,
      query,
      results: results.slice(0, numResults),
      totalResults: results.length,
      engine: 'duckduckgo',
    };
  } catch (error) {
    console.error('Web search error:', error);
    return {
      success: false,
      query,
      error: error.message,
      results: [],
    };
  }
}

/**
 * Fetch URL and extract main content
 */
export async function fetchUrl(url) {
  try {
    // Validate URL
    const parsedUrl = new URL(url);
    if (!['http:', 'https:'].includes(parsedUrl.protocol)) {
      throw new Error('Only HTTP/HTTPS URLs are supported');
    }

    const response = await fetch(url, {
      headers: {
        'User-Agent':
          'Mozilla/5.0 (compatible; OnelastAI/1.0; +https://mumtaz.ai)',
        Accept:
          'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      },
      redirect: 'follow',
      signal: AbortSignal.timeout(10000), // 10 second timeout
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch URL: ${response.status}`);
    }

    const html = await response.text();

    // Parse HTML and extract content
    const dom = new JSDOM(html);
    const document = dom.window.document;

    // Remove unwanted elements
    const unwantedSelectors = [
      'script',
      'style',
      'nav',
      'header',
      'footer',
      'aside',
      '.advertisement',
      '.ads',
      '.sidebar',
      '.navigation',
      '[role="navigation"]',
      '[role="banner"]',
      '[role="complementary"]',
    ];
    unwantedSelectors.forEach((selector) => {
      document.querySelectorAll(selector).forEach((el) => el.remove());
    });

    // Extract title
    const title = document.querySelector('title')?.textContent?.trim() || '';

    // Extract meta description
    const metaDesc =
      document
        .querySelector('meta[name="description"]')
        ?.getAttribute('content') || '';

    // Try to find main content
    let mainContent = '';
    const contentSelectors = [
      'article',
      'main',
      '[role="main"]',
      '.content',
      '.post-content',
      '.article-body',
      '.entry-content',
      '#content',
      '.main-content',
    ];

    for (const selector of contentSelectors) {
      const element = document.querySelector(selector);
      if (element) {
        mainContent = element.textContent || '';
        break;
      }
    }

    // Fallback to body if no main content found
    if (!mainContent) {
      mainContent = document.body?.textContent || '';
    }

    // Clean up the content
    mainContent = mainContent
      .replace(/\s+/g, ' ')
      .replace(/\n\s*\n/g, '\n')
      .trim()
      .slice(0, 8000); // Limit content length

    return {
      success: true,
      url,
      title,
      description: metaDesc,
      content: mainContent,
      contentLength: mainContent.length,
    };
  } catch (error) {
    console.error('URL fetch error:', error);
    return {
      success: false,
      url,
      error: error.message,
    };
  }
}

/**
 * Get weather data from OpenWeatherMap
 */
export async function getWeather(location, units = 'metric', forecast = false) {
  const apiKey = process.env.OPENWEATHERMAP_API_KEY;
  if (!apiKey) {
    return { success: false, error: 'OpenWeatherMap API key not configured' };
  }

  const unitLabel = units === 'imperial' ? '°F' : units === 'metric' ? '°C' : 'K';
  const speedLabel = units === 'imperial' ? 'mph' : 'm/s';

  try {
    // Current weather
    const currentUrl = `https://api.openweathermap.org/data/2.5/weather?q=${encodeURIComponent(location)}&units=${units}&appid=${apiKey}`;
    const currentRes = await fetch(currentUrl, { signal: AbortSignal.timeout(10000) });
    
    if (!currentRes.ok) {
      const errData = await currentRes.json().catch(() => ({}));
      throw new Error(errData.message || `Weather API returned ${currentRes.status}`);
    }

    const current = await currentRes.json();
    const result = {
      success: true,
      location: `${current.name}, ${current.sys?.country || ''}`,
      coordinates: { lat: current.coord?.lat, lon: current.coord?.lon },
      current: {
        temperature: `${Math.round(current.main.temp)}${unitLabel}`,
        feels_like: `${Math.round(current.main.feels_like)}${unitLabel}`,
        temp_min: `${Math.round(current.main.temp_min)}${unitLabel}`,
        temp_max: `${Math.round(current.main.temp_max)}${unitLabel}`,
        humidity: `${current.main.humidity}%`,
        pressure: `${current.main.pressure} hPa`,
        condition: current.weather?.[0]?.main || 'Unknown',
        description: current.weather?.[0]?.description || '',
        icon: current.weather?.[0]?.icon ? `https://openweathermap.org/img/wn/${current.weather[0].icon}@2x.png` : null,
        wind: {
          speed: `${current.wind?.speed || 0} ${speedLabel}`,
          direction: current.wind?.deg ? `${current.wind.deg}°` : 'N/A',
        },
        visibility: current.visibility ? `${(current.visibility / 1000).toFixed(1)} km` : 'N/A',
        clouds: `${current.clouds?.all || 0}%`,
        sunrise: current.sys?.sunrise ? new Date(current.sys.sunrise * 1000).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }) : null,
        sunset: current.sys?.sunset ? new Date(current.sys.sunset * 1000).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }) : null,
      },
    };

    // Optional 5-day forecast
    if (forecast) {
      const forecastUrl = `https://api.openweathermap.org/data/2.5/forecast?q=${encodeURIComponent(location)}&units=${units}&appid=${apiKey}`;
      const forecastRes = await fetch(forecastUrl, { signal: AbortSignal.timeout(10000) });
      
      if (forecastRes.ok) {
        const forecastData = await forecastRes.json();
        // Group by day and take one reading per day (noon)
        const dailyMap = {};
        for (const item of forecastData.list || []) {
          const date = item.dt_txt?.split(' ')[0];
          const hour = item.dt_txt?.split(' ')[1];
          if (!date) continue;
          // Prefer noon reading, or first available
          if (!dailyMap[date] || hour === '12:00:00') {
            dailyMap[date] = {
              date,
              temperature: `${Math.round(item.main.temp)}${unitLabel}`,
              temp_min: `${Math.round(item.main.temp_min)}${unitLabel}`,
              temp_max: `${Math.round(item.main.temp_max)}${unitLabel}`,
              humidity: `${item.main.humidity}%`,
              condition: item.weather?.[0]?.main || 'Unknown',
              description: item.weather?.[0]?.description || '',
              wind_speed: `${item.wind?.speed || 0} ${speedLabel}`,
            };
          }
        }
        result.forecast = Object.values(dailyMap).slice(0, 5);
      }
    }

    console.log(`[get_weather] Weather for ${result.location}: ${result.current.temperature}, ${result.current.description}`);
    return result;
  } catch (error) {
    console.error('[get_weather] Error:', error.message);
    return {
      success: false,
      location,
      error: error.message,
    };
  }
}

/**
 * Get current time with timezone support
 */
export function getCurrentTime(timezone = 'UTC') {
  try {
    const now = new Date();
    const options = {
      timeZone: timezone,
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      weekday: 'long',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    };

    const formatter = new Intl.DateTimeFormat('en-US', options);
    const formatted = formatter.format(now);

    return {
      success: true,
      timezone,
      formatted,
      iso: now.toISOString(),
      unix: Math.floor(now.getTime() / 1000),
    };
  } catch (_error) {
    return {
      success: false,
      error: `Invalid timezone: ${timezone}`,
      formatted: new Date().toISOString(),
    };
  }
}

/**
 * Safe mathematical expression evaluator
 */
export function calculate(expression) {
  try {
    // Strict whitelist tokenizer — rejects any character not in the allowed set
    let remaining = expression.replace(/\s+/g, '');
    const tokens = [];

    while (remaining.length > 0) {
      // Number (including decimals and scientific notation like 1.5e10)
      let m = remaining.match(/^(\d+\.?\d*(?:e[+-]?\d+)?)/i);
      if (m) { tokens.push(m[0]); remaining = remaining.slice(m[0].length); continue; }

      // Operator, paren, comma, percent, caret
      m = remaining.match(/^([+\-*/().%^,])/);
      if (m) { tokens.push(m[0]); remaining = remaining.slice(1); continue; }

      // Known math function names
      m = remaining.match(/^(sqrt|sin|cos|tan|log|ln|exp|abs|floor|ceil|round|pow|min|max|pi)/i);
      if (m) { tokens.push(m[0]); remaining = remaining.slice(m[0].length); continue; }

      // Standalone 'e' for Euler's number (not followed by alpha)
      if (/^e(?![a-z])/i.test(remaining)) {
        tokens.push('e'); remaining = remaining.slice(1); continue;
      }

      throw new Error(`Invalid character in expression: "${remaining[0]}"`);
    }

    if (tokens.length === 0) throw new Error('Empty expression');

    // Rebuild from validated tokens and replace with Math.* equivalents
    const prepared = tokens.join('')
      .replace(/\^/g, '**')
      .replace(/sqrt\(/gi, 'Math.sqrt(')
      .replace(/sin\(/gi, 'Math.sin(')
      .replace(/cos\(/gi, 'Math.cos(')
      .replace(/tan\(/gi, 'Math.tan(')
      .replace(/log\(/gi, 'Math.log10(')
      .replace(/ln\(/gi, 'Math.log(')
      .replace(/exp\(/gi, 'Math.exp(')
      .replace(/abs\(/gi, 'Math.abs(')
      .replace(/floor\(/gi, 'Math.floor(')
      .replace(/ceil\(/gi, 'Math.ceil(')
      .replace(/round\(/gi, 'Math.round(')
      .replace(/pow\(/gi, 'Math.pow(')
      .replace(/min\(/gi, 'Math.min(')
      .replace(/max\(/gi, 'Math.max(')
      .replace(/\bpi\b/gi, 'Math.PI')
      .replace(/\be\b/gi, 'Math.E');

    // eslint-disable-next-line no-new-func
    const result = new Function(`"use strict"; return (${prepared})`)();

    if (typeof result !== 'number' || !isFinite(result)) {
      throw new Error('Result is not a valid number');
    }

    return {
      success: true,
      expression,
      result,
      formatted: result.toLocaleString('en-US', { maximumFractionDigits: 10 }),
    };
  } catch (error) {
    return {
      success: false,
      expression,
      error: `Could not evaluate: ${error.message}`,
    };
  }
}

// ═══════════════════════════════════════════════════════════════════
// FILE OPERATIONS - Database + S3 Hybrid Storage
// Text files < 1MB → Database
// Binary files & large files → S3
// ═══════════════════════════════════════════════════════════════════

// Helper to determine MIME type from filename
function getMimeType(filename) {
  const ext = path.extname(filename).toLowerCase();
  const mimeTypes = {
    '.txt': 'text/plain',
    '.md': 'text/markdown',
    '.json': 'application/json',
    '.js': 'application/javascript',
    '.ts': 'application/typescript',
    '.py': 'text/x-python',
    '.html': 'text/html',
    '.css': 'text/css',
    '.csv': 'text/csv',
    '.xml': 'application/xml',
    '.yaml': 'text/yaml',
    '.yml': 'text/yaml',
    '.sh': 'application/x-sh',
    '.sql': 'application/sql',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.gif': 'image/gif',
    '.webp': 'image/webp',
    '.svg': 'image/svg+xml',
    '.mp4': 'video/mp4',
    '.webm': 'video/webm',
    '.mp3': 'audio/mpeg',
    '.wav': 'audio/wav',
    '.pdf': 'application/pdf',
    '.zip': 'application/zip',
  };
  return mimeTypes[ext] || 'application/octet-stream';
}

// Sanitize folder path
function sanitizePath(folder) {
  if (!folder || folder === '/') return '/';
  // Remove leading/trailing slashes and normalize
  return '/' + folder.replace(/^\/+|\/+$/g, '').replace(/\.\.+/g, '');
}

/**
 * Create a new file with content - HYBRID STORAGE (Database + S3)
 * - Text files < 1MB → Database
 * - Binary files (images, videos, etc.) → S3
 * - Large files > 1MB → S3
 */
export async function createFile(
  filename,
  content,
  folder = '',
  userId = 'default',
  agentId = null
) {
  try {
    const sanitizedFilename = path.basename(filename);
    const sanitizedFolder = sanitizePath(folder);
    const filePath =
      sanitizedFolder === '/'
        ? `/${sanitizedFilename}`
        : `${sanitizedFolder}/${sanitizedFilename}`;
    const mimeType = getMimeType(sanitizedFilename);

    // Check if file already exists
    const existingFile = await AgentFile.findOne({
      userId,
      path: filePath,
      isDeleted: false,
    });

    if (existingFile) {
      return {
        success: false,
        error: `File already exists: ${sanitizedFilename}. Use modify_file to update it.`,
        filename: sanitizedFilename,
      };
    }

    // Determine storage type
    const isBinary = isBinaryFile(sanitizedFilename);
    const contentBuffer =
      typeof content === 'string' ? Buffer.from(content, 'utf-8') : content;
    const size = contentBuffer.length;
    const useS3 = isBinary || size > MAX_DATABASE_SIZE;

    let storageType = 'database';
    let s3Key = null;
    let s3Url = null;
    let storedContent = null;

    if (useS3) {
      // Upload to S3
      s3Key = `agent-files/${userId}/${agentId}${filePath}`;
      const s3Result = await uploadToS3(s3Key, contentBuffer, mimeType);

      if (!s3Result.success) {
        // Fallback to database if S3 fails
        console.warn(
          `[AgentFiles] S3 upload failed, falling back to database: ${s3Result.error}`
        );
        storageType = 'database';
        storedContent = isBinary ? contentBuffer.toString('base64') : content;
      } else {
        storageType = 's3';
        s3Url = s3Result.url;
        console.log(`[AgentFiles] Stored in S3: ${s3Key}`);
      }
    } else {
      // Store in database (PostgreSQL)
      storedContent = content;
    }

    // Create file document
    const newFile = new AgentFile({
      userId,
      agentId,
      filename: sanitizedFilename,
      originalName: sanitizedFilename,
      folder: sanitizedFolder,
      path: filePath,
      mimeType,
      size,
      storageType,
      content: storedContent,
      s3Key,
      s3Bucket: useS3 && storageType === 's3' ? S3_BUCKET : null,
      s3Url,
    });

    await newFile.save();

    console.log(
      `[AgentFiles] Created file: ${filePath} for user ${userId} (${size} bytes, ${storageType})`
    );

    return {
      success: true,
      filename: sanitizedFilename,
      folder: sanitizedFolder,
      path: filePath,
      size,
      message: `File created successfully: ${sanitizedFilename}`,
      downloadUrl: `/api/agents/files/download?path=${encodeURIComponent(filePath)}&userId=${userId}`,
      storedIn: storageType,
      s3Url: s3Url || undefined,
    };
  } catch (error) {
    console.error('[AgentFiles] Create error:', error);
    return {
      success: false,
      filename,
      error: error.message,
    };
  }
}

/**
 * Read file contents - FROM DATABASE
 */
export async function readFile(filename, userId = 'default') {
  try {
    // Handle both filename and full path
    const searchPath = filename.startsWith('/') ? filename : `/${filename}`;

    const file = await AgentFile.findOne({
      userId,
      $or: [{ path: searchPath }, { filename }],
      isDeleted: false,
    });

    if (!file) {
      return {
        success: false,
        filename,
        error: `File not found: ${filename}`,
      };
    }

    // Get content based on storage type
    let content = file.content;

    if (file.storageType === 's3' && file.s3Key) {
      // Download from S3
      const s3Result = await downloadFromS3(file.s3Key);
      if (s3Result.success) {
        // For text files, convert to string
        const isBinary = isBinaryFile(file.filename);
        content = isBinary
          ? s3Result.content.toString('base64')
          : s3Result.content.toString('utf-8');
      } else {
        return {
          success: false,
          filename,
          error: `Failed to download from S3: ${s3Result.error}`,
        };
      }
    }

    return {
      success: true,
      filename: file.filename,
      path: file.path,
      content,
      size: file.size,
      mimeType: file.mimeType,
      modified: file.updatedAt.toISOString(),
      created: file.createdAt.toISOString(),
      storageType: file.storageType,
      s3Url: file.s3Url || undefined,
    };
  } catch (error) {
    console.error('[AgentFiles] Read error:', error);
    return {
      success: false,
      filename,
      error: error.message,
    };
  }
}

/**
 * Modify an existing file - IN DATABASE
 */
export async function modifyFile(
  filename,
  content,
  mode = 'replace',
  userId = 'default',
  find = null,
  line = null
) {
  try {
    const searchPath = filename.startsWith('/') ? filename : `/${filename}`;

    const file = await AgentFile.findOne({
      userId,
      $or: [{ path: searchPath }, { filename }],
      isDeleted: false,
    });

    if (!file) {
      return {
        success: false,
        filename,
        error: `File not found: ${filename}. Use create_file to create it first.`,
      };
    }

    const oldContent = file.content || '';

    // Update content based on mode
    if (mode === 'append') {
      file.content = oldContent + content;
    } else if (mode === 'find_replace') {
      if (!find) {
        return {
          success: false,
          filename,
          error: 'find_replace mode requires the "find" parameter with text to search for.',
        };
      }
      if (!oldContent.includes(find)) {
        return {
          success: false,
          filename,
          error: `Text not found in file: "${find.substring(0, 100)}${find.length > 100 ? '...' : ''}"`,
        };
      }
      file.content = oldContent.replace(find, content);
    } else if (mode === 'insert_at_line') {
      const lineNum = parseInt(line, 10);
      if (!lineNum || lineNum < 1) {
        return {
          success: false,
          filename,
          error: 'insert_at_line mode requires "line" parameter (1-based line number).',
        };
      }
      const lines = oldContent.split('\n');
      const insertIdx = Math.min(lineNum - 1, lines.length);
      lines.splice(insertIdx, 0, content);
      file.content = lines.join('\n');
    } else {
      // Default: replace entire content
      file.content = content;
    }

    file.size = Buffer.byteLength(file.content, 'utf-8');
    file.updatedAt = new Date();

    await file.save();

    console.log(
      `[AgentFiles] Modified file: ${file.path} (${mode}, ${file.size} bytes)`
    );

    return {
      success: true,
      filename: file.filename,
      path: file.path,
      mode,
      size: file.size,
      message: `File modified (${mode}): ${file.filename}`,
    };
  } catch (error) {
    console.error('[AgentFiles] Modify error:', error);
    return {
      success: false,
      filename,
      error: error.message,
    };
  }
}

/**
 * List files in a directory - FROM DATABASE
 */
export async function listFiles(folder = '', userId = 'default') {
  try {
    const sanitizedFolder = sanitizePath(folder);

    // Find all files for user in this folder (not recursive)
    const files = await AgentFile.find({
      userId,
      folder: sanitizedFolder,
      isDeleted: false,
    }).sort({ filename: 1 });

    // Get unique subfolders
    const allFiles = await AgentFile.find({
      userId,
      isDeleted: false,
      folder: { $regex: `^${sanitizedFolder}`, $ne: sanitizedFolder },
    });

    const subfolders = new Set();
    allFiles.forEach((f) => {
      const relativePath = f.folder
        .replace(sanitizedFolder, '')
        .replace(/^\//, '');
      const firstFolder = relativePath.split('/')[0];
      if (firstFolder) subfolders.add(firstFolder);
    });

    const result = [
      ...Array.from(subfolders).map((name) => ({
        name,
        type: 'folder',
        size: null,
        modified: null,
      })),
      ...files.map((f) => ({
        name: f.filename,
        type: 'file',
        size: f.size,
        mimeType: f.mimeType,
        modified: f.updatedAt.toISOString(),
        version: f.version,
        path: f.path,
      })),
    ];

    return {
      success: true,
      folder: sanitizedFolder,
      files: result,
      totalFiles: files.length,
      totalFolders: subfolders.size,
      storage: 'database',
    };
  } catch (error) {
    console.error('[AgentFiles] List error:', error);
    return {
      success: false,
      folder: folder || '/',
      error: error.message,
    };
  }
}

/**
 * Check if a file or folder exists - NO ERROR, just true/false
 */
export async function fileExists(path, userId = 'default') {
  try {
    const searchPath = path.startsWith('/') ? path : `/${path}`;
    const filename = path.split('/').pop();

    // Check as file
    const file = await AgentFile.findOne({
      userId,
      $or: [{ path: searchPath }, { filename }],
      isDeleted: false,
    });

    if (file) {
      return {
        success: true,
        exists: true,
        type: 'file',
        path: file.path,
        filename: file.filename,
        size: file.size,
      };
    }

    // Check as folder (any files with this folder prefix)
    const folderFiles = await AgentFile.findOne({
      userId,
      folder: { $regex: `^${searchPath}` },
      isDeleted: false,
    });

    if (folderFiles) {
      return {
        success: true,
        exists: true,
        type: 'folder',
        path: searchPath,
      };
    }

    return {
      success: true,
      exists: false,
      path: searchPath,
    };
  } catch (error) {
    console.error('[AgentFiles] Exists check error:', error);
    return {
      success: true,
      exists: false,
      path,
      error: error.message,
    };
  }
}

/**
 * Get full project tree - recursive directory listing
 */
export async function getProjectTree(folder = '', userId = 'default', maxDepth = 10) {
  try {
    const sanitizedFolder = sanitizePath(folder);

    // Get ALL files for this user
    const allFiles = await AgentFile.find({
      userId,
      isDeleted: false,
      ...(sanitizedFolder && sanitizedFolder !== '/'
        ? { folder: { $regex: `^${sanitizedFolder}` } }
        : {}),
    }).sort({ path: 1 });

    // Build tree structure
    const tree = {};
    let totalFiles = 0;
    let totalSize = 0;

    for (const file of allFiles) {
      const parts = file.path.split('/').filter(Boolean);
      let current = tree;

      // Build nested structure
      for (let i = 0; i < parts.length; i++) {
        const part = parts[i];
        const depth = i + 1;
        if (depth > maxDepth) break;

        if (i === parts.length - 1) {
          // Leaf file
          current[part] = {
            type: 'file',
            size: file.size,
            mimeType: file.mimeType,
            modified: file.updatedAt?.toISOString(),
          };
          totalFiles++;
          totalSize += file.size || 0;
        } else {
          // Directory
          if (!current[part] || current[part].type === 'file') {
            current[part] = { type: 'folder', children: {} };
          }
          current = current[part].children || current[part];
        }
      }
    }

    // Format tree as text for easy reading
    function formatTree(node, prefix = '', isLast = true) {
      let output = '';
      const entries = Object.entries(node).filter(([k]) => k !== 'type' && k !== 'children');
      entries.forEach(([name, info], i) => {
        const last = i === entries.length - 1;
        const connector = last ? '└── ' : '├── ';
        const nextPrefix = prefix + (last ? '    ' : '│   ');

        if (info.type === 'folder') {
          output += `${prefix}${connector}📁 ${name}/\n`;
          if (info.children) {
            output += formatTree(info.children, nextPrefix, last);
          }
        } else {
          const sizeStr = info.size ? ` (${info.size} bytes)` : '';
          output += `${prefix}${connector}📄 ${name}${sizeStr}\n`;
        }
      });
      return output;
    }

    const treeText = formatTree(tree);

    return {
      success: true,
      folder: sanitizedFolder || '/',
      tree: treeText || '(empty project)',
      totalFiles,
      totalSize,
      storage: 'database',
    };
  } catch (error) {
    console.error('[AgentFiles] Project tree error:', error);
    return {
      success: false,
      folder: folder || '/',
      error: error.message,
    };
  }
}

/**
 * Write file - UPSERT: create if not exists, overwrite if exists
 */
export async function writeFile(filename, content, folder = '', userId = 'default', agentId = null) {
  try {
    const sanitizedFolder = sanitizePath(folder);
    const sanitizedFilename = filename.replace(/[^a-zA-Z0-9._\-\/]/g, '_');
    const filePath = `${sanitizedFolder}/${sanitizedFilename}`.replace(
      /\/+/g,
      '/'
    );

    // Check if file already exists
    const existing = await AgentFile.findOne({
      userId,
      $or: [{ path: filePath }, { filename: sanitizedFilename, folder: sanitizedFolder }],
      isDeleted: false,
    });

    if (existing) {
      // Overwrite existing file
      existing.content = content;
      existing.size = Buffer.byteLength(content, 'utf-8');
      existing.updatedAt = new Date();
      await existing.save();

      console.log(`[AgentFiles] write_file overwrite: ${existing.path} (${existing.size} bytes)`);

      return {
        success: true,
        filename: existing.filename,
        path: existing.path,
        size: existing.size,
        action: 'overwritten',
        message: `File overwritten: ${existing.filename}`,
        downloadUrl: `/api/agents/files/download?path=${encodeURIComponent(existing.path)}&userId=${userId}`,
      };
    }

    // Create new file — delegate to createFile
    return createFile(filename, content, folder, userId, agentId);
  } catch (error) {
    console.error('[AgentFiles] Write error:', error);
    return {
      success: false,
      filename,
      error: error.message,
    };
  }
}

/**
 * Delete a file - SOFT DELETE IN DATABASE + DELETE FROM S3
 */
export async function deleteFile(filename, userId = 'default') {
  try {
    const searchPath = filename.startsWith('/') ? filename : `/${filename}`;

    const file = await AgentFile.findOne({
      userId,
      $or: [{ path: searchPath }, { filename }],
      isDeleted: false,
    });

    if (!file) {
      return {
        success: false,
        filename,
        error: `File not found: ${filename}`,
      };
    }

    // Delete from S3 if stored there
    if (file.storageType === 's3' && file.s3Key) {
      const s3Result = await deleteFromS3(file.s3Key);
      if (!s3Result.success) {
        console.warn(
          `[AgentFiles] Failed to delete from S3: ${s3Result.error}`
        );
      }
    }

    // Soft delete in Database
    file.isDeleted = true;
    file.updatedAt = new Date();
    await file.save();

    console.log(
      `[AgentFiles] Deleted file: ${file.path} (was in ${file.storageType})`
    );

    return {
      success: true,
      filename: file.filename,
      path: file.path,
      message: `File deleted successfully: ${file.filename}`,
    };
  } catch (error) {
    console.error('[AgentFiles] Delete error:', error);
    if (error.code === 'ENOENT') {
      return {
        success: false,
        filename,
        error: `File not found: ${filename}`,
      };
    }
    return {
      success: false,
      filename,
      error: error.message,
    };
  }
}

