// IMAGE & VIDEO GENERATION
// ═══════════════════════════════════════════════════════════════════

// Style → DALL-E 3 prompt modifiers + vivid/natural setting
const DALLE_STYLE_MAP = {
  realistic:     { dalleStyle: 'natural',  modifier: '' },
  artistic:      { dalleStyle: 'vivid',    modifier: ', artistic painting, creative expression, vibrant colors' },
  anime:         { dalleStyle: 'vivid',    modifier: ', anime style, manga art, Japanese animation, cel-shaded' },
  'oil-painting':{ dalleStyle: 'natural',  modifier: ', oil painting, classical art, textured brushstrokes, rich colors' },
  watercolor:    { dalleStyle: 'vivid',    modifier: ', watercolor painting, soft colors, flowing edges, delicate' },
  'digital-art': { dalleStyle: 'vivid',    modifier: ', digital art, modern illustration, clean lines, vibrant' },
  '3d-render':   { dalleStyle: 'vivid',    modifier: ', 3D render, octane render, detailed lighting, photorealistic CGI' },
  'pixel-art':   { dalleStyle: 'vivid',    modifier: ', pixel art, retro 8-bit style, nostalgic gaming aesthetic' },
};

// Map arbitrary width×height to DALL-E 3 supported sizes
function mapToDalleSize(width, height) {
  const ratio = width / height;
  if (ratio > 1.3) return '1792x1024';      // Landscape
  if (ratio < 0.77) return '1024x1792';      // Portrait
  return '1024x1024';                         // Square (default)
}

/**
 * Generate an AI image using OpenAI DALL-E 3
 * Direct backend call — no frontend proxy, no base64, URL-based flow.
 */
export async function generateImage(
  prompt,
  style = 'realistic',
  width = 1024,
  height = 1024,
  userId = 'default',
  agentId = null
) {
  try {
    const OPENAI_API_KEY = process.env.OPENAI_API_KEY;
    if (!OPENAI_API_KEY) {
      return {
        success: false,
        prompt,
        error: 'Image generation service not configured (missing OpenAI API key)',
      };
    }

    // Map style to DALL-E 3 parameters
    const styleConfig = DALLE_STYLE_MAP[style] || DALLE_STYLE_MAP.realistic;
    const enhancedPrompt = `${prompt}${styleConfig.modifier}`;
    const dalleSize = mapToDalleSize(width, height);

    console.log(`[ImageGen] DALL-E 3: "${prompt.substring(0, 60)}..." style=${style} size=${dalleSize}`);

    // 1. Call OpenAI DALL-E 3 directly — returns a temporary URL (no base64)
    const response = await fetch('https://api.openai.com/v1/images/generations', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: 'dall-e-3',
        prompt: enhancedPrompt,
        n: 1,
        size: dalleSize,
        quality: 'standard',
        style: styleConfig.dalleStyle,
      }),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error?.message || `DALL-E 3 request failed: ${response.status}`);
    }

    const data = await response.json();
    const tempUrl = data.data?.[0]?.url;
    const revisedPrompt = data.data?.[0]?.revised_prompt;

    if (!tempUrl) {
      throw new Error('DALL-E 3 returned no image URL');
    }

    // 2. Download the image from OpenAI's temporary URL
    const imageResponse = await fetch(tempUrl);
    if (!imageResponse.ok) {
      throw new Error(`Failed to download generated image: ${imageResponse.status}`);
    }
    const imageBuffer = Buffer.from(await imageResponse.arrayBuffer());

    // 3. Upload to S3 for permanent storage
    const filename = `generated-image-${Date.now()}.png`;
    const saveResult = await createFile(
      filename,
      imageBuffer,
      '/images',
      userId,
      agentId
    );

    if (saveResult.success) {
      return {
        success: true,
        prompt,
        revisedPrompt,
        style,
        dimensions: dalleSize.replace('x', '×'),
        url: saveResult.s3Url || saveResult.downloadUrl,
        s3Url: saveResult.s3Url,
        filename: saveResult.filename,
        path: saveResult.path,
        downloadUrl: saveResult.downloadUrl,
        message: 'Image generated and saved successfully! You can view or download it.',
      };
    }

    // S3 failed — return the temporary OpenAI URL as fallback (expires in ~1 hour)
    console.warn('[ImageGen] S3 upload failed, returning temporary DALL-E URL:', saveResult.error);
    return {
      success: true,
      prompt,
      revisedPrompt,
      style,
      dimensions: dalleSize.replace('x', '×'),
      url: tempUrl,
      downloadUrl: tempUrl,
      warning: 'Image saved to temporary storage. Link may expire — download it soon.',
      message: 'Image generated successfully! Note: using temporary link, download recommended.',
    };
  } catch (error) {
    console.error('[ImageGen] Error:', error);
    return {
      success: false,
      prompt,
      error: error.message || 'Failed to generate image',
    };
  }
}

/**
 * Generate a short AI video using Replicate
 */
export async function generateVideo(prompt, duration = 4, userId = 'default') {
  try {
    const REPLICATE_API_TOKEN = process.env.REPLICATE_API_TOKEN;

    if (!REPLICATE_API_TOKEN) {
      return {
        success: false,
        prompt,
        error: 'Video generation service not configured',
      };
    }

    // Use Replicate's video generation model (Stable Video Diffusion or similar)
    const response = await fetch('https://api.replicate.com/v1/predictions', {
      method: 'POST',
      headers: {
        Authorization: `Token ${REPLICATE_API_TOKEN}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        // Using animate-diff or similar video model
        version:
          'a4a8bafd6089e1716b06057c42b19378250d008b80fe87caa5cd36d40c1eda90', // AnimateDiff-Lightning
        input: {
          prompt,
          num_frames: Math.min(duration * 8, 32), // ~8 fps, max 32 frames
          guidance_scale: 7.5,
        },
      }),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.detail || 'Video generation request failed');
    }

    const prediction = await response.json();

    // Poll for completion (video generation takes time)
    let result = prediction;
    let attempts = 0;
    const maxAttempts = 60; // 5 minutes max wait

    while (
      result.status !== 'succeeded' &&
      result.status !== 'failed' &&
      attempts < maxAttempts
    ) {
      await new Promise((resolve) => setTimeout(resolve, 5000)); // Wait 5 seconds

      const pollResponse = await fetch(
        `https://api.replicate.com/v1/predictions/${result.id}`,
        {
          headers: { Authorization: `Token ${REPLICATE_API_TOKEN}` },
        }
      );
      result = await pollResponse.json();
      attempts++;
    }

    if (result.status === 'failed') {
      throw new Error(result.error || 'Video generation failed');
    }

    if (result.status !== 'succeeded') {
      return {
        success: true,
        prompt,
        status: 'processing',
        predictionId: result.id,
        message:
          'Video is being generated. This may take a few minutes. Check back soon!',
        checkUrl: `https://api.replicate.com/v1/predictions/${result.id}`,
      };
    }

    // Video completed - save to workspace
    const videoUrl = result.output;
    if (videoUrl) {
      try {
        const videoResponse = await fetch(videoUrl);
        const videoBuffer = Buffer.from(await videoResponse.arrayBuffer());
        const filename = `generated-video-${Date.now()}.mp4`;

        // Use createFile to properly store in Database/S3
        const saveResult = await createFile(
          filename,
          videoBuffer,
          '/videos',
          userId,
          'video-generator'
        );

        if (saveResult.success) {
          return {
            success: true,
            prompt,
            duration: `~${duration}s`,
            videoUrl,
            filename: saveResult.filename,
            path: saveResult.path,
            downloadUrl: saveResult.downloadUrl,
            s3Url: saveResult.s3Url,
            message:
              'Video generated and saved successfully! You can view or download it.',
          };
        } else {
          // Return URL even if save fails
          return {
            success: true,
            prompt,
            videoUrl,
            warning: 'Video generated but could not be saved to workspace',
            message:
              'Video generated! Click to view. (Note: Could not save to workspace)',
          };
        }
      } catch (saveError) {
        // Return URL even if save fails
        console.error('Failed to save video:', saveError);
        return {
          success: true,
          prompt,
          videoUrl,
          message: 'Video generated! Click to view.',
        };
      }
    }

    return {
      success: false,
      prompt,
      error: 'No video output received',
    };
  } catch (error) {
    console.error('Video generation error:', error);
    return {
      success: false,
      prompt,
      error: error.message || 'Failed to generate video',
    };
  }
}

