/**
 * Create a folder
 */
export async function createFolder(folderPath, userId = 'default') {
  try {
    const sanitizedFolder = sanitizePath(folderPath);

    // Create a placeholder file to represent the folder
    const placeholderFile = new AgentFile({
      userId,
      filename: '.folder',
      folder: sanitizedFolder,
      path: `${sanitizedFolder}/.folder`,
      mimeType: 'application/x-directory',
      size: 0,
      storageType: 'database',
      content: '',
    });

    await placeholderFile.save();

    return {
      success: true,
      folder: sanitizedFolder,
      message: `Folder created: ${sanitizedFolder}`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

/**
 * List only folders
 */
export async function listFolders(parentFolder = '', userId = 'default') {
  try {
    const sanitizedFolder = sanitizePath(parentFolder);

    const files = await AgentFile.find({
      userId,
      isDeleted: false,
    });

    const folders = new Set();
    files.forEach((f) => {
      if (
        f.folder !== sanitizedFolder &&
        f.folder.startsWith(sanitizedFolder)
      ) {
        const relativePath = f.folder
          .replace(sanitizedFolder, '')
          .replace(/^\//, '');
        const firstFolder = relativePath.split('/')[0];
        if (firstFolder) folders.add(firstFolder);
      }
    });

    return {
      success: true,
      parentFolder: sanitizedFolder,
      folders: Array.from(folders).map((name) => ({ name, type: 'folder' })),
      totalFolders: folders.size,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

/**
 * Move a file
 */
export async function moveFile(source, destination, userId = 'default') {
  try {
    const file = await AgentFile.findOne({
      userId,
      path: source,
      isDeleted: false,
    });
    if (!file) return { success: false, error: `File not found: ${source}` };

    const destFolder = path.dirname(destination);
    const destFilename = path.basename(destination);

    file.folder = sanitizePath(destFolder);
    file.filename = destFilename;
    file.path = destination;
    await file.save();

    return {
      success: true,
      source,
      destination,
      message: `File moved from ${source} to ${destination}`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

/**
 * Copy a file
 */
export async function copyFile(source, destination, userId = 'default') {
  try {
    const file = await AgentFile.findOne({
      userId,
      path: source,
      isDeleted: false,
    });
    if (!file) return { success: false, error: `File not found: ${source}` };

    const destFolder = path.dirname(destination);
    const destFilename = path.basename(destination);

    const newFile = new AgentFile({
      userId,
      agentId: file.agentId,
      filename: destFilename,
      originalName: destFilename,
      folder: sanitizePath(destFolder),
      path: destination,
      mimeType: file.mimeType,
      size: file.size,
      storageType: file.storageType,
      content: file.content,
    });

    await newFile.save();

    return {
      success: true,
      source,
      destination,
      message: `File copied from ${source} to ${destination}`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

/**
 * Rename a file
 */
export async function renameFile(oldName, newName, userId = 'default') {
  try {
    const file = await AgentFile.findOne({
      userId,
      $or: [{ path: oldName }, { filename: oldName }],
      isDeleted: false,
    });
    if (!file) return { success: false, error: `File not found: ${oldName}` };

    const newPath = file.path.replace(file.filename, newName);
    file.filename = newName;
    file.originalName = newName;
    file.path = newPath;
    file.mimeType = getMimeType(newName);
    await file.save();

    return {
      success: true,
      oldName,
      newName,
      message: `File renamed from ${oldName} to ${newName}`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

/**
 * Zip files
 */
export async function zipFiles(
  filePaths,
  outputName = 'archive.zip',
  userId = 'default'
) {
  try {
    const archiver = await import('archiver')
      .then((m) => m.default)
      .catch(() => null);
    if (!archiver) {
      return { success: false, error: 'Archiver not available' };
    }

    const files = await AgentFile.find({
      userId,
      path: { $in: filePaths },
      isDeleted: false,
    });

    if (files.length === 0) {
      return { success: false, error: 'No files found to zip' };
    }

    // Create zip in memory
    const chunks = [];
    const archive = archiver('zip', { zlib: { level: 9 } });

    archive.on('data', (chunk) => chunks.push(chunk));

    for (const file of files) {
      archive.append(file.content, { name: file.filename });
    }

    await archive.finalize();
    const zipBuffer = Buffer.concat(chunks);

    // Upload ZIP to S3 for reliable storage
    const s3Key = `agent-files/${userId}/archives/${outputName}`;
    const uploadResult = await uploadToS3(s3Key, zipBuffer, 'application/zip');

    const zipFile = new AgentFile({
      userId,
      filename: outputName,
      folder: '/',
      path: `/${outputName}`,
      mimeType: 'application/zip',
      size: zipBuffer.length,
      s3Key,
      s3Url: uploadResult.success ? uploadResult.url : undefined,
    });

    await zipFile.save();

    return {
      success: true,
      filename: outputName,
      size: zipBuffer.length,
      filesIncluded: files.length,
      url: uploadResult.success ? uploadResult.url : undefined,
      message: `Created ${outputName} with ${files.length} files`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

/**
 * Unzip files
 */
export async function unzipFiles(
  zipFile,
  destination = '',
  userId = 'default'
) {
  try {
    const file = await AgentFile.findOne({
      userId,
      $or: [{ path: zipFile }, { filename: zipFile }],
      isDeleted: false,
    });

    if (!file)
      return { success: false, error: `ZIP file not found: ${zipFile}` };

    const unzipper = await import('unzipper')
      .then((m) => m.default)
      .catch(() => null);
    if (!unzipper) {
      return { success: false, error: 'Unzipper not available' };
    }

    const zipBuffer = Buffer.from(file.content, 'base64');
    const directory = await unzipper.Open.buffer(zipBuffer);

    const extractedFiles = [];
    const destFolder = sanitizePath(destination);

    for (const entry of directory.files) {
      if (entry.type === 'File') {
        const content = await entry.buffer();
        const entryMimeType = getMimeType(entry.path);
        const isBinary = BINARY_EXTENSIONS.some(ext => entry.path.toLowerCase().endsWith(ext));

        let fileData;
        if (isBinary || content.length > MAX_DATABASE_SIZE) {
          // Store binary/large files in S3
          const s3Key = `agent-files/${userId}/extracted/${Date.now()}-${entry.path.replace(/\//g, '_')}`;
          const uploadResult = await uploadToS3(s3Key, content, entryMimeType);
          fileData = {
            userId,
            filename: entry.path,
            folder: destFolder,
            path: `${destFolder}/${entry.path}`,
            mimeType: entryMimeType,
            size: content.length,
            s3Key,
            s3Url: uploadResult.success ? uploadResult.url : undefined,
          };
        } else {
          fileData = {
            userId,
            filename: entry.path,
            folder: destFolder,
            path: `${destFolder}/${entry.path}`,
            mimeType: entryMimeType,
            size: content.length,
            storageType: 'database',
            content: content.toString('utf-8'),
          };
        }

        const newFile = new AgentFile(fileData);
        await newFile.save();
        extractedFiles.push(entry.path);
      }
    }

    return {
      success: true,
      extractedFiles,
      destination: destFolder,
      message: `Extracted ${extractedFiles.length} files to ${destFolder}`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

