/**
 * think_step_by_step — structured reasoning (returns template for AI to fill)
 */
export async function thinkStepByStep(topic, depth = 'normal') {
  const steps = depth === 'brief' ? 3 : depth === 'deep' ? 8 : 5;
  return {
    success: true,
    topic,
    depth,
    framework: {
      steps: Array.from({ length: steps }, (_, i) => `Step ${i + 1}: [analysis]`),
      sections: ['Understanding', 'Key Factors', 'Pros', 'Cons', 'Analysis', 'Conclusion'],
      instruction: `Analyze "${topic}" using ${steps}-step structured reasoning. Fill in each step with detailed analysis.`,
    },
    message: `Structured ${depth} analysis framework created for: "${topic}"`,
  };
}

/**
 * generate_code — returns a code generation instruction (AI fills the code)
 */
export async function generateCode(description, language, style = 'documented') {
  return {
    success: true,
    description,
    language,
    style,
    instruction: `Generate ${style} ${language} code that: ${description}`,
    template: {
      language,
      style,
      sections: style === 'production'
        ? ['imports', 'types', 'implementation', 'error_handling', 'exports', 'tests']
        : style === 'documented'
          ? ['description', 'implementation', 'usage_example']
          : ['implementation'],
    },
    message: `Code generation request processed: ${language} (${style} style)`,
  };
}

/**
 * debug_code — analyze code for bugs
 */
export async function debugCode(code, language, errorMessage) {
  const issues = [];
  
  // Basic static analysis patterns
  if (code.includes('return a - b') && (code.includes('add') || code.includes('Add') || code.includes('sum'))) {
    issues.push({ type: 'logic_error', line: 'return statement', description: 'Function named "add" but uses subtraction (-) instead of addition (+)', severity: 'high', fix: 'Change "return a - b" to "return a + b"' });
  }
  if (code.includes('==') && !code.includes('===')) {
    issues.push({ type: 'best_practice', description: 'Uses loose equality (==) instead of strict equality (===)', severity: 'medium', fix: 'Replace == with ===' });
  }
  if (code.includes('var ')) {
    issues.push({ type: 'best_practice', description: 'Uses "var" instead of "let" or "const"', severity: 'low', fix: 'Replace "var" with "let" or "const"' });
  }
  if (/catch\s*\(\s*\)\s*\{/.test(code)) {
    issues.push({ type: 'error_handling', description: 'Empty catch block swallows errors silently', severity: 'medium', fix: 'Log or handle the error in the catch block' });
  }
  if (/console\.log/.test(code) && !code.includes('// debug')) {
    issues.push({ type: 'cleanup', description: 'Contains console.log statements (potential debug leftover)', severity: 'low', fix: 'Remove or guard console.log statements' });
  }

  return {
    success: true,
    code: code.slice(0, 500),
    language: language || 'auto-detected',
    error_message: errorMessage || null,
    issues,
    issue_count: issues.length,
    message: issues.length > 0
      ? `Found ${issues.length} issue(s) in the code`
      : 'No obvious issues detected — manual review recommended',
  };
}

