/**
 * run_command — execute shell commands via child_process
 */
export async function runCommand(command, timeout = 10000) {
  try {
    // Block dangerous commands
    const blocked = /\b(rm\s+-rf\s+\/|mkfs|dd\s+if|format|shutdown|reboot|passwd|sudo\s+rm|curl.*\|\s*sh|wget.*\|\s*sh)\b/i;
    if (blocked.test(command)) {
      return { success: false, error: 'Command blocked for safety reasons' };
    }

    const { execSync } = await import('child_process');
    const output = execSync(command, {
      timeout: Math.min(timeout, 30000),
      encoding: 'utf-8',
      maxBuffer: 1024 * 1024,
      cwd: process.cwd(),
    });

    return {
      success: true,
      command,
      output: output.trim(),
      message: `Command executed successfully`,
    };
  } catch (error) {
    return {
      success: false,
      command,
      error: error.stderr || error.message,
      exitCode: error.status,
    };
  }
}

/**
 * git_status — show git status
 */
export async function gitStatus(directory) {
  return runCommand(`cd ${directory || '.'} && git status --porcelain && echo "---BRANCH---" && git branch --show-current`);
}

/**
 * git_log — show git log
 */
export async function gitLog(count = 10, branch, directory) {
  const branchArg = branch ? ` ${branch}` : '';
  return runCommand(`cd ${directory || '.'} && git log --oneline --decorate -${count}${branchArg}`);
}

