// V2.0 UPGRADED TOOLS — ALL use PostgreSQL via Prisma for storage
// ═══════════════════════════════════════════════════════════════════

// ─── HELPER: Log tool usage to DB ───
async function logToolUsage(toolName, command, args, userId, agentId, status = 'completed', latencyMs = 0) {
  try {
    await prisma.toolUsage.create({
      data: {
        toolName,
        command,
        arguments: args ? JSON.parse(JSON.stringify(args)) : {},
        userId: userId || undefined,
        agentId: agentId || undefined,
        status,
        latencyMs,
        occurredAt: new Date(),
      },
    });
  } catch (_e) {
    // Foreign key constraint on userId — retry without userId/agentId
    try {
      await prisma.toolUsage.create({
        data: {
          toolName,
          command,
          arguments: args ? JSON.parse(JSON.stringify(args)) : {},
          status,
          latencyMs,
          occurredAt: new Date(),
        },
      });
    } catch (_e2) {
      // Non-critical — don't break tool execution if logging fails
    }
  }
}

// ─── DOCUMENT PARSING ───

export async function parseJson(input, schema, transform, userId = 'default') {
  const start = Date.now();
  try {
    let data;
    if (typeof input === 'string') {
      data = JSON.parse(input);
    } else {
      data = input;
    }

    const result = { success: true, parsed: data, type: typeof data };

    // Schema validation
    if (schema) {
      const errors = [];
      if (schema.required && Array.isArray(schema.required)) {
        for (const key of schema.required) {
          if (!(key in data)) errors.push(`Missing required field: ${key}`);
        }
      }
      if (schema.properties && typeof data === 'object') {
        for (const [key, def] of Object.entries(schema.properties)) {
          if (key in data && def.type && typeof data[key] !== def.type) {
            errors.push(`Field "${key}" should be ${def.type}, got ${typeof data[key]}`);
          }
        }
      }
      result.validation = { valid: errors.length === 0, errors };
    }

    // Transform
    if (transform === 'keys') result.keys = Object.keys(data);
    else if (transform === 'values') result.values = Object.values(data);
    else if (transform === 'flatten') {
      const flat = {};
      const flatten = (obj, prefix = '') => {
        for (const [k, v] of Object.entries(obj)) {
          const key = prefix ? `${prefix}.${k}` : k;
          if (v && typeof v === 'object' && !Array.isArray(v)) flatten(v, key);
          else flat[key] = v;
        }
      };
      flatten(data);
      result.flattened = flat;
    }

    result.stats = {
      keys: typeof data === 'object' ? Object.keys(data).length : 0,
      isArray: Array.isArray(data),
      depth: JSON.stringify(data).split('{').length - 1,
      sizeBytes: JSON.stringify(data).length,
    };

    await logToolUsage('parse_json', 'parse', { transform, hasSchema: !!schema }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    await logToolUsage('parse_json', 'parse', {}, userId, null, 'failed', Date.now() - start);
    return { success: false, error: `JSON parse error: ${error.message}` };
  }
}

export async function parseMarkdown(input, userId = 'default') {
  const start = Date.now();
  try {
    const lines = input.split('\n');
    const headers = [];
    const links = [];
    const codeBlocks = [];
    const images = [];
    let frontmatter = null;

    // Extract frontmatter
    if (lines[0] === '---') {
      const endIdx = lines.indexOf('---', 1);
      if (endIdx > 0) {
        const fmLines = lines.slice(1, endIdx);
        frontmatter = {};
        for (const line of fmLines) {
          const colonIdx = line.indexOf(':');
          if (colonIdx > 0) {
            frontmatter[line.slice(0, colonIdx).trim()] = line.slice(colonIdx + 1).trim();
          }
        }
      }
    }

    // Extract headers
    for (let i = 0; i < lines.length; i++) {
      const match = lines[i].match(/^(#{1,6})\s+(.+)/);
      if (match) headers.push({ level: match[1].length, text: match[2], line: i + 1 });
    }

    // Extract links
    const linkRegex = /\[([^\]]*)\]\(([^)]+)\)/g;
    let m;
    while ((m = linkRegex.exec(input)) !== null) {
      links.push({ text: m[1], url: m[2] });
    }

    // Extract images
    const imgRegex = /!\[([^\]]*)\]\(([^)]+)\)/g;
    while ((m = imgRegex.exec(input)) !== null) {
      images.push({ alt: m[1], src: m[2] });
    }

    // Extract code blocks
    let inCode = false;
    let codeLang = '';
    let codeContent = [];
    for (const line of lines) {
      if (line.startsWith('```') && !inCode) {
        inCode = true;
        codeLang = line.slice(3).trim();
        codeContent = [];
      } else if (line.startsWith('```') && inCode) {
        codeBlocks.push({ language: codeLang || 'text', content: codeContent.join('\n') });
        inCode = false;
      } else if (inCode) {
        codeContent.push(line);
      }
    }

    const result = {
      success: true,
      headers,
      links,
      images,
      codeBlocks,
      frontmatter,
      stats: {
        totalLines: lines.length,
        headerCount: headers.length,
        linkCount: links.length,
        imageCount: images.length,
        codeBlockCount: codeBlocks.length,
        hasFrontmatter: !!frontmatter,
        wordCount: input.split(/\s+/).filter(Boolean).length,
      },
    };

    await logToolUsage('parse_markdown', 'parse', { lines: lines.length }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function parseHtml(input, selector, extract = 'text', userId = 'default') {
  const start = Date.now();
  try {
    const dom = new JSDOM(input);
    const doc = dom.window.document;

    const result = { success: true };

    if (selector) {
      const elements = doc.querySelectorAll(selector);
      result.matches = Array.from(elements).map(el => {
        if (extract === 'html') return el.innerHTML;
        if (extract === 'attributes') {
          const attrs = {};
          for (const attr of el.attributes) attrs[attr.name] = attr.value;
          return attrs;
        }
        return el.textContent.trim();
      });
      result.count = result.matches.length;
    } else {
      // Full document analysis
      result.title = doc.title || '';
      result.meta = Array.from(doc.querySelectorAll('meta')).map(m => ({
        name: m.getAttribute('name') || m.getAttribute('property') || '',
        content: m.getAttribute('content') || '',
      })).filter(m => m.name || m.content);
      result.headings = Array.from(doc.querySelectorAll('h1,h2,h3,h4,h5,h6')).map(h => ({
        level: parseInt(h.tagName[1]),
        text: h.textContent.trim(),
      }));
      result.links = Array.from(doc.querySelectorAll('a[href]')).map(a => ({
        text: a.textContent.trim(),
        href: a.getAttribute('href'),
      }));
      result.images = Array.from(doc.querySelectorAll('img')).map(img => ({
        src: img.getAttribute('src') || '',
        alt: img.getAttribute('alt') || '',
      }));
      result.forms = doc.querySelectorAll('form').length;
      result.scripts = doc.querySelectorAll('script').length;
      result.text = doc.body?.textContent?.trim().slice(0, 5000) || '';
    }

    await logToolUsage('parse_html', 'parse', { selector, extract }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    return { success: false, error: error.message };
  }
}

// ─── IMAGE OCR ───

export async function imageOcr(file, language = 'eng', format = 'text', userId = 'default') {
  const start = Date.now();
  try {
    // Delegate to image_ai with OCR action for actual processing
    const aiResult = await imageAI({
      file,
      action: 'describe',
      prompt: `Extract ALL text visible in this image. Return the raw text exactly as it appears, preserving layout where possible. Language hint: ${language}`,
      userId,
    });

    const extractedText = aiResult?.description || aiResult?.text || aiResult?.analysis || '';

    const result = {
      success: true,
      text: extractedText,
      language,
      format,
      confidence: extractedText.length > 10 ? 0.85 : 0.3,
      wordCount: extractedText.split(/\s+/).filter(Boolean).length,
      charCount: extractedText.length,
    };

    if (format === 'json') {
      result.lines = extractedText.split('\n').filter(Boolean).map((line, i) => ({
        lineNumber: i + 1,
        text: line.trim(),
      }));
    }

    await logToolUsage('image_ocr', 'ocr', { file, language }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    await logToolUsage('image_ocr', 'ocr', { file }, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message };
  }
}

// ─── DEVELOPER TOOLS (4 NEW) ───

export async function devTest(action = 'run', framework = 'auto', testPath, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    const { exec } = await import('child_process');
    const { promisify } = await import('util');
    const execAsync = promisify(exec);

    let cmd;
    const fw = framework === 'auto' ? 'npx jest' : framework;

    switch (action) {
      case 'run':
        cmd = testPath ? `${fw} ${testPath} --no-coverage 2>&1` : `${fw} --no-coverage 2>&1`;
        break;
      case 'coverage':
        cmd = testPath ? `${fw} ${testPath} --coverage 2>&1` : `${fw} --coverage 2>&1`;
        break;
      case 'watch':
        return { success: true, message: 'Watch mode should be run via terminal. Use run_command tool with the test watch command.' };
      case 'list':
        cmd = `${fw} --listTests 2>&1`;
        break;
      default:
        cmd = `${fw} ${action} 2>&1`;
    }

    const timeout = options.timeout || 30000;
    const { stdout, stderr } = await execAsync(cmd, { timeout, maxBuffer: 1024 * 1024 });
    const output = stdout || stderr || '';

    // Parse test results
    const passed = (output.match(/(\d+) passed/)?.[1]) || 0;
    const failed = (output.match(/(\d+) failed/)?.[1]) || 0;
    const skipped = (output.match(/(\d+) skipped/)?.[1]) || 0;

    const result = {
      success: true,
      action,
      framework: fw,
      output: output.slice(0, 5000),
      summary: { passed: +passed, failed: +failed, skipped: +skipped, total: +passed + +failed + +skipped },
    };

    await logToolUsage('dev_test', action, { framework: fw, testPath }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    await logToolUsage('dev_test', action, {}, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message, output: error.stdout || error.stderr || '' };
  }
}

export async function devGit(action = 'status', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    const { exec } = await import('child_process');
    const { promisify } = await import('util');
    const execAsync = promisify(exec);
    const cwd = options.directory || process.cwd();

    let cmd;
    switch (action) {
      case 'status': cmd = 'git status --porcelain'; break;
      case 'log': cmd = `git log --oneline -${options.count || 10}`; break;
      case 'diff': cmd = `git diff ${options.staged ? '--staged' : ''} ${options.file || ''}`; break;
      case 'branch': cmd = 'git branch -a'; break;
      case 'commit':
        if (!options.message) return { success: false, error: 'Commit message required' };
        cmd = `git add ${options.files || '-A'} && git commit -m "${options.message.replace(/"/g, '\\"')}"`;
        break;
      case 'push': cmd = `git push ${options.remote || 'origin'} ${options.branch || ''}`; break;
      case 'pull': cmd = `git pull ${options.remote || 'origin'} ${options.branch || ''}`; break;
      case 'clone':
        if (!options.url) return { success: false, error: 'Repository URL required' };
        cmd = `git clone ${options.url} ${options.destination || ''}`;
        break;
      case 'blame': cmd = `git blame ${options.file || ''}`; break;
      case 'stash': cmd = `git stash ${options.subaction || 'list'}`; break;
      case 'tag': cmd = `git tag ${options.name || '-l'}`; break;
      case 'remote': cmd = 'git remote -v'; break;
      case 'history':
        cmd = `git log --pretty=format:"%h|%an|%ad|%s" --date=short -${options.count || 20} ${options.file ? `-- ${options.file}` : ''}`;
        break;
      default: cmd = `git ${action}`;
    }

    const { stdout, stderr } = await execAsync(cmd, { cwd, timeout: 30000 });
    const output = stdout || stderr || '';

    const result = { success: true, action, output: output.trim().slice(0, 10000) };

    if (action === 'status') {
      const lines = output.trim().split('\n').filter(Boolean);
      result.files = lines.map(l => ({
        status: l.slice(0, 2).trim(),
        file: l.slice(3).trim(),
      }));
      result.clean = lines.length === 0;
    } else if (action === 'history') {
      result.commits = output.trim().split('\n').filter(Boolean).map(l => {
        const [hash, author, date, ...msgParts] = l.split('|');
        return { hash, author, date, message: msgParts.join('|') };
      });
    }

    // Store git action in DB
    await logToolUsage('dev_git', action, { cwd }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    await logToolUsage('dev_git', action, {}, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message, output: error.stdout || error.stderr || '' };
  }
}

export async function devNpm(action = 'list', packageName, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    const { exec } = await import('child_process');
    const { promisify } = await import('util');
    const execAsync = promisify(exec);
    const cwd = options.directory || process.cwd();

    let cmd;
    switch (action) {
      case 'install': cmd = `npm install ${packageName || ''} ${options.dev ? '--save-dev' : ''}`; break;
      case 'uninstall': cmd = `npm uninstall ${packageName || ''}`; break;
      case 'update': cmd = `npm update ${packageName || ''}`; break;
      case 'list': cmd = 'npm list --depth=0 --json 2>/dev/null'; break;
      case 'outdated': cmd = 'npm outdated --json 2>/dev/null'; break;
      case 'audit': cmd = 'npm audit --json 2>/dev/null'; break;
      case 'info': cmd = `npm info ${packageName || ''} --json 2>/dev/null`; break;
      case 'search': cmd = `npm search ${packageName || ''} --json 2>/dev/null`; break;
      case 'run': cmd = `npm run ${options.script || 'build'} 2>&1`; break;
      case 'init': cmd = 'npm init -y'; break;
      case 'version': cmd = `npm version ${options.bump || 'patch'}`; break;
      default: cmd = `npm ${action} ${packageName || ''}`;
    }

    const { stdout, stderr } = await execAsync(cmd, { cwd, timeout: 60000, maxBuffer: 2 * 1024 * 1024 });
    const output = stdout || stderr || '';

    let parsed = null;
    try { parsed = JSON.parse(output); } catch (_) { /* not JSON output */ }

    const result = {
      success: true,
      action,
      package: packageName || null,
      output: parsed || output.trim().slice(0, 10000),
    };

    if (action === 'audit' && parsed) {
      result.vulnerabilities = parsed.metadata?.vulnerabilities || {};
      result.totalVulnerabilities = Object.values(parsed.metadata?.vulnerabilities || {}).reduce((a, b) => a + b, 0);
    }

    await logToolUsage('dev_npm', action, { packageName }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    await logToolUsage('dev_npm', action, {}, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message, output: error.stdout || error.stderr || '' };
  }
}

export async function devDocker(action = 'ps', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    const { exec } = await import('child_process');
    const { promisify } = await import('util');
    const execAsync = promisify(exec);

    let cmd;
    switch (action) {
      case 'ps': cmd = 'docker ps --format "{{.ID}}|{{.Image}}|{{.Status}}|{{.Names}}|{{.Ports}}"'; break;
      case 'images': cmd = 'docker images --format "{{.Repository}}:{{.Tag}}|{{.Size}}|{{.ID}}"'; break;
      case 'build':
        cmd = `docker build -t ${options.tag || 'app:latest'} ${options.context || '.'}`;
        break;
      case 'run':
        cmd = `docker run -d ${options.ports ? `-p ${options.ports}` : ''} ${options.env ? options.env.map(e => `-e ${e}`).join(' ') : ''} ${options.image || ''}`;
        break;
      case 'stop': cmd = `docker stop ${options.container || ''}`; break;
      case 'rm': cmd = `docker rm ${options.container || ''}`; break;
      case 'logs': cmd = `docker logs ${options.tail ? `--tail ${options.tail}` : '--tail 100'} ${options.container || ''}`; break;
      case 'compose-up': cmd = `docker compose up -d ${options.services || ''}`; break;
      case 'compose-down': cmd = 'docker compose down'; break;
      case 'inspect': cmd = `docker inspect ${options.container || options.image || ''}`; break;
      case 'stats': cmd = 'docker stats --no-stream --format "{{.Name}}|{{.CPUPerc}}|{{.MemUsage}}|{{.NetIO}}"'; break;
      case 'prune': cmd = 'docker system prune -f'; break;
      default: cmd = `docker ${action}`;
    }

    const { stdout, stderr } = await execAsync(cmd, { timeout: 60000 });
    const output = stdout || stderr || '';

    const result = { success: true, action, output: output.trim().slice(0, 10000) };

    if (action === 'ps') {
      result.containers = output.trim().split('\n').filter(Boolean).map(l => {
        const [id, image, status, name, ports] = l.split('|');
        return { id, image, status, name, ports };
      });
    } else if (action === 'images') {
      result.images = output.trim().split('\n').filter(Boolean).map(l => {
        const [repo, size, id] = l.split('|');
        return { repository: repo, size, id };
      });
    }

    await logToolUsage('dev_docker', action, options, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    await logToolUsage('dev_docker', action, {}, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message };
  }
}

