export async function webScreenshot(url, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    // Use fetch to get page HTML and create a text representation
    const response = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0 OnelastAI/2.0' }, signal: AbortSignal.timeout(15000) });
    const html = await response.text();
    const dom = new JSDOM(html);
    const doc = dom.window.document;

    const result = {
      success: true,
      url,
      title: doc.title || '',
      status: response.status,
      viewport: options.viewport || '1920x1080',
      format: options.format || 'png',
      message: 'Screenshot captured as text representation. For actual screenshots, use a headless browser service.',
      textContent: doc.body?.textContent?.trim().slice(0, 3000) || '',
      meta: {
        description: doc.querySelector('meta[name="description"]')?.getAttribute('content') || '',
        ogImage: doc.querySelector('meta[property="og:image"]')?.getAttribute('content') || '',
      },
    };

    await logToolUsage('web_screenshot', 'capture', { url }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function webLighthouse(url, categories = ['performance', 'accessibility', 'seo'], userId = 'default') {
  const start = Date.now();
  try {
    // Fetch the page and analyze what we can
    const response = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0 OnelastAI/2.0' }, signal: AbortSignal.timeout(15000) });
    const html = await response.text();
    const dom = new JSDOM(html);
    const doc = dom.window.document;
    const loadTime = Date.now() - start;

    const issues = [];
    const scores = {};

    // Performance checks
    if (categories.includes('performance')) {
      const scripts = doc.querySelectorAll('script');
      const stylesheets = doc.querySelectorAll('link[rel="stylesheet"]');
      const images = doc.querySelectorAll('img');
      const imgsWithoutLazy = Array.from(images).filter(img => !img.getAttribute('loading'));
      if (scripts.length > 10) issues.push({ category: 'performance', severity: 'warning', message: `${scripts.length} script tags found — consider bundling` });
      if (imgsWithoutLazy.length > 3) issues.push({ category: 'performance', severity: 'info', message: `${imgsWithoutLazy.length} images without lazy loading` });
      scores.performance = Math.max(0, 100 - scripts.length * 2 - stylesheets.length * 3 - Math.min(loadTime / 50, 30));
    }

    // SEO checks
    if (categories.includes('seo')) {
      if (!doc.title) issues.push({ category: 'seo', severity: 'error', message: 'Missing <title> tag' });
      if (!doc.querySelector('meta[name="description"]')) issues.push({ category: 'seo', severity: 'error', message: 'Missing meta description' });
      if (!doc.querySelector('h1')) issues.push({ category: 'seo', severity: 'warning', message: 'No <h1> tag found' });
      if (!doc.querySelector('link[rel="canonical"]')) issues.push({ category: 'seo', severity: 'info', message: 'No canonical URL' });
      const seoErrors = issues.filter(i => i.category === 'seo').length;
      scores.seo = Math.max(0, 100 - seoErrors * 15);
    }

    // Accessibility checks
    if (categories.includes('accessibility')) {
      const imgsWithoutAlt = Array.from(doc.querySelectorAll('img')).filter(i => !i.getAttribute('alt'));
      const formsWithoutLabels = doc.querySelectorAll('input:not([aria-label]):not([id])').length;
      if (imgsWithoutAlt.length) issues.push({ category: 'accessibility', severity: 'warning', message: `${imgsWithoutAlt.length} images without alt text` });
      if (formsWithoutLabels) issues.push({ category: 'accessibility', severity: 'warning', message: `${formsWithoutLabels} inputs without labels` });
      if (!doc.documentElement.getAttribute('lang')) issues.push({ category: 'accessibility', severity: 'error', message: 'Missing lang attribute on <html>' });
      const a11yErrors = issues.filter(i => i.category === 'accessibility').length;
      scores.accessibility = Math.max(0, 100 - a11yErrors * 12);
    }

    const result = {
      success: true,
      url,
      loadTimeMs: loadTime,
      scores,
      issues,
      summary: {
        totalIssues: issues.length,
        errors: issues.filter(i => i.severity === 'error').length,
        warnings: issues.filter(i => i.severity === 'warning').length,
        htmlSize: html.length,
      },
    };

    await logToolUsage('web_lighthouse', 'audit', { url, categories }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function webScrape(url, selectors = {}, format = 'json', userId = 'default') {
  const start = Date.now();
  try {
    const response = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0 OnelastAI/2.0' }, signal: AbortSignal.timeout(15000) });
    const html = await response.text();
    const dom = new JSDOM(html);
    const doc = dom.window.document;

    const data = {};

    if (selectors && Object.keys(selectors).length > 0) {
      for (const [key, selector] of Object.entries(selectors)) {
        const els = doc.querySelectorAll(selector);
        data[key] = Array.from(els).map(el => el.textContent.trim());
      }
    } else {
      // Auto-extract common data
      data.title = doc.title || '';
      data.headings = Array.from(doc.querySelectorAll('h1,h2,h3')).map(h => h.textContent.trim());
      data.paragraphs = Array.from(doc.querySelectorAll('p')).slice(0, 20).map(p => p.textContent.trim()).filter(Boolean);
      data.links = Array.from(doc.querySelectorAll('a[href]')).slice(0, 50).map(a => ({
        text: a.textContent.trim(),
        href: a.getAttribute('href'),
      }));
      data.tables = Array.from(doc.querySelectorAll('table')).map(table => {
        const rows = Array.from(table.querySelectorAll('tr'));
        return rows.map(row => Array.from(row.querySelectorAll('td,th')).map(cell => cell.textContent.trim()));
      });
      data.jsonLd = Array.from(doc.querySelectorAll('script[type="application/ld+json"]')).map(s => {
        try { return JSON.parse(s.textContent); } catch { return null; }
      }).filter(Boolean);
    }

    const result = {
      success: true,
      url,
      status: response.status,
      data,
      format,
      extractedAt: new Date().toISOString(),
    };

    // Store scrape result in DB
    await logToolUsage('web_scrape', 'scrape', { url, selectors: Object.keys(selectors) }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    return { success: false, error: error.message };
  }
}

// ─── DATABASE TOOLS (6 NEW) — ALL use Prisma/PostgreSQL ───

export async function dbQuery(query, params = [], options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!query) return { success: false, error: 'SQL query required' };

    // Security: block destructive operations unless explicitly allowed
    const upperQuery = query.trim().toUpperCase();
    const isRead = upperQuery.startsWith('SELECT') || upperQuery.startsWith('EXPLAIN') || upperQuery.startsWith('SHOW');
    const isDangerous = upperQuery.includes('DROP ') || upperQuery.includes('TRUNCATE ') || upperQuery.includes('ALTER ');

    if (isDangerous && !options.allowDestructive) {
      return { success: false, error: 'Destructive queries (DROP/TRUNCATE/ALTER) require allowDestructive: true' };
    }

    let result;
    if (isRead) {
      result = await prisma.$queryRawUnsafe(query, ...params);
    } else {
      result = await prisma.$executeRawUnsafe(query, ...params);
    }

    const response = {
      success: true,
      query: query.slice(0, 500),
      type: isRead ? 'select' : 'execute',
      data: isRead ? result : undefined,
      rowCount: isRead ? (Array.isArray(result) ? result.length : 0) : result,
      executionTimeMs: Date.now() - start,
    };

    await logToolUsage('db_query', 'query', { queryType: isRead ? 'read' : 'write' }, userId, null, 'completed', Date.now() - start);
    return response;
  } catch (error) {
    await logToolUsage('db_query', 'query', {}, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message };
  }
}

export async function dbSchema(action = 'inspect', tableName, definition, userId = 'default') {
  const start = Date.now();
  try {
    let result;

    switch (action) {
      case 'inspect': {
        // List all tables
        const tables = await prisma.$queryRawUnsafe(
          `SELECT table_name, table_type FROM information_schema.tables WHERE table_schema = 'public' ORDER BY table_name`
        );
        const tableDetails = [];
        for (const t of tables.slice(0, 50)) {
          const cols = await prisma.$queryRawUnsafe(
            `SELECT column_name, data_type, is_nullable, column_default FROM information_schema.columns WHERE table_name = $1 ORDER BY ordinal_position`,
            t.table_name
          );
          tableDetails.push({
            name: t.table_name,
            type: t.table_type,
            columns: cols.map(c => ({
              name: c.column_name,
              type: c.data_type,
              nullable: c.is_nullable === 'YES',
              default: c.column_default,
            })),
          });
        }
        result = { success: true, action: 'inspect', tables: tableDetails, count: tableDetails.length };
        break;
      }
      case 'describe': {
        if (!tableName) return { success: false, error: 'Table name required for describe' };
        const cols = await prisma.$queryRawUnsafe(
          `SELECT column_name, data_type, is_nullable, column_default, character_maximum_length
           FROM information_schema.columns WHERE table_name = $1 ORDER BY ordinal_position`,
          tableName
        );
        const indexes = await prisma.$queryRawUnsafe(
          `SELECT indexname, indexdef FROM pg_indexes WHERE tablename = $1`,
          tableName
        );
        const constraints = await prisma.$queryRawUnsafe(
          `SELECT conname, contype, pg_get_constraintdef(oid) as definition
           FROM pg_constraint WHERE conrelid = $1::regclass`,
          tableName
        );
        result = {
          success: true,
          action: 'describe',
          table: tableName,
          columns: cols,
          indexes: indexes,
          constraints: constraints,
          columnCount: cols.length,
        };
        break;
      }
      case 'tables': {
        const tables = await prisma.$queryRawUnsafe(
          `SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' ORDER BY table_name`
        );
        result = { success: true, action: 'tables', tables: tables.map(t => t.table_name), count: tables.length };
        break;
      }
      default:
        result = { success: false, error: `Unknown schema action: ${action}. Use inspect, describe, or tables.` };
    }

    await logToolUsage('db_schema', action, { tableName }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function dbBackup(action = 'export', tableName, format = 'json', userId = 'default') {
  const start = Date.now();
  try {
    switch (action) {
      case 'export': {
        if (!tableName) return { success: false, error: 'Table name required for export' };
        const data = await prisma.$queryRawUnsafe(`SELECT * FROM "${tableName}" LIMIT 10000`);
        const exportData = {
          table: tableName,
          exportedAt: new Date().toISOString(),
          rowCount: data.length,
          data,
        };

        // Store backup metadata in DB
        await prisma.toolUsage.create({
          data: {
            toolName: 'db_backup',
            command: 'export',
            arguments: { tableName, rowCount: data.length },
            userId: userId || undefined,
            status: 'completed',
            latencyMs: Date.now() - start,
            occurredAt: new Date(),
          },
        });

        return {
          success: true,
          action: 'export',
          table: tableName,
          rowCount: data.length,
          format,
          data: format === 'json' ? exportData : JSON.stringify(exportData),
          sizeBytes: JSON.stringify(exportData).length,
        };
      }
      case 'snapshot': {
        // Get all table counts as a snapshot
        const tables = await prisma.$queryRawUnsafe(
          `SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' ORDER BY table_name`
        );
        const snapshot = [];
        for (const t of tables) {
          try {
            const countResult = await prisma.$queryRawUnsafe(`SELECT COUNT(*) as count FROM "${t.table_name}"`);
            snapshot.push({ table: t.table_name, rowCount: Number(countResult[0]?.count || 0) });
          } catch { snapshot.push({ table: t.table_name, rowCount: -1, error: 'count failed' }); }
        }

        await logToolUsage('db_backup', 'snapshot', {}, userId, null, 'completed', Date.now() - start);
        return {
          success: true,
          action: 'snapshot',
          tables: snapshot,
          totalTables: snapshot.length,
          totalRows: snapshot.reduce((a, t) => a + Math.max(0, t.rowCount), 0),
          snapshotAt: new Date().toISOString(),
        };
      }
      default:
        return { success: false, error: `Unknown backup action: ${action}. Use export or snapshot.` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function dbMigrate(action = 'status', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    const { exec } = await import('child_process');
    const { promisify } = await import('util');
    const execAsync = promisify(exec);

    let cmd;
    switch (action) {
      case 'status': cmd = 'npx prisma migrate status 2>&1'; break;
      case 'push': cmd = 'npx prisma db push 2>&1'; break;
      case 'generate': cmd = 'npx prisma generate 2>&1'; break;
      case 'create':
        if (!options.name) return { success: false, error: 'Migration name required' };
        cmd = `npx prisma migrate dev --name ${options.name} 2>&1`;
        break;
      case 'deploy': cmd = 'npx prisma migrate deploy 2>&1'; break;
      case 'reset': cmd = 'npx prisma migrate reset --force 2>&1'; break;
      default: return { success: false, error: `Unknown migrate action: ${action}` };
    }

    const { stdout, stderr } = await execAsync(cmd, { timeout: 60000, cwd: process.cwd() });

    await logToolUsage('db_migrate', action, options, userId, null, 'completed', Date.now() - start);
    return { success: true, action, output: (stdout || stderr || '').trim().slice(0, 5000) };
  } catch (error) {
    await logToolUsage('db_migrate', action, {}, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message, output: error.stdout || error.stderr || '' };
  }
}

export async function dbAnalyze(query, tableName, userId = 'default') {
  const start = Date.now();
  try {
    if (query) {
      const plan = await prisma.$queryRawUnsafe(`EXPLAIN (ANALYZE, BUFFERS, FORMAT JSON) ${query}`);
      await logToolUsage('db_analyze', 'explain', { query: query.slice(0, 200) }, userId, null, 'completed', Date.now() - start);
      return {
        success: true,
        action: 'explain',
        query: query.slice(0, 500),
        plan: plan,
        executionTimeMs: Date.now() - start,
      };
    }

    if (tableName) {
      const stats = await prisma.$queryRawUnsafe(
        `SELECT relname, n_live_tup, n_dead_tup, last_vacuum, last_autovacuum, last_analyze
         FROM pg_stat_user_tables WHERE relname = $1`,
        tableName
      );
      const size = await prisma.$queryRawUnsafe(
        `SELECT pg_size_pretty(pg_total_relation_size($1)) as total_size,
                pg_size_pretty(pg_relation_size($1)) as table_size,
                pg_size_pretty(pg_indexes_size($1::regclass)) as index_size`,
        tableName
      );

      await logToolUsage('db_analyze', 'stats', { tableName }, userId, null, 'completed', Date.now() - start);
      return {
        success: true,
        action: 'stats',
        table: tableName,
        statistics: stats[0] || {},
        size: size[0] || {},
      };
    }

    return { success: false, error: 'Provide either a query to explain or a tableName to analyze' };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function dbConnect(action = 'status', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    switch (action) {
      case 'status': {
        // Test current Prisma/PostgreSQL connection
        const result = await prisma.$queryRawUnsafe('SELECT version(), current_database(), current_user, pg_postmaster_start_time()');
        await logToolUsage('db_connect', 'status', {}, userId, null, 'completed', Date.now() - start);
        return {
          success: true,
          action: 'status',
          connected: true,
          provider: 'postgresql',
          database: result[0]?.current_database,
          user: result[0]?.current_user,
          version: result[0]?.version?.split(' ').slice(0, 2).join(' '),
          upSince: result[0]?.pg_postmaster_start_time,
          latencyMs: Date.now() - start,
        };
      }
      case 'pool': {
        const metrics = await prisma.$metrics?.json?.() || {};
        return { success: true, action: 'pool', metrics };
      }
      case 'databases': {
        const dbs = await prisma.$queryRawUnsafe('SELECT datname, pg_size_pretty(pg_database_size(datname)) as size FROM pg_database WHERE datistemplate = false');
        return { success: true, action: 'databases', databases: dbs };
      }
      default:
        return { success: false, error: `Unknown connect action: ${action}. Use status, pool, or databases.` };
    }
  } catch (error) {
    return { success: false, error: error.message, connected: false };
  }
}

// ─── API & INTEGRATIONS (7 NEW) ───

export async function apiRequest(url, method = 'GET', headers = {}, body = null, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!url) return { success: false, error: 'URL required' };

    const fetchOptions = {
      method: method.toUpperCase(),
      headers: {
        'User-Agent': 'OnelastAI-API/2.0',
        ...headers,
      },
      signal: AbortSignal.timeout(options.timeout || 30000),
    };

    if (body && !['GET', 'HEAD'].includes(method.toUpperCase())) {
      fetchOptions.body = typeof body === 'string' ? body : JSON.stringify(body);
      if (!headers['Content-Type'] && !headers['content-type']) {
        fetchOptions.headers['Content-Type'] = 'application/json';
      }
    }

    if (options.auth) {
      if (options.auth.type === 'bearer') fetchOptions.headers['Authorization'] = `Bearer ${options.auth.token}`;
      else if (options.auth.type === 'basic') fetchOptions.headers['Authorization'] = `Basic ${Buffer.from(`${options.auth.username}:${options.auth.password}`).toString('base64')}`;
      else if (options.auth.type === 'apikey') fetchOptions.headers[options.auth.headerName || 'X-API-Key'] = options.auth.key;
    }

    const response = await fetch(url, fetchOptions);
    const contentType = response.headers.get('content-type') || '';
    let responseData;

    if (contentType.includes('json')) {
      responseData = await response.json();
    } else {
      responseData = await response.text();
      if (responseData.length > 10000) responseData = responseData.slice(0, 10000) + '...[truncated]';
    }

    const result = {
      success: true,
      status: response.status,
      statusText: response.statusText,
      headers: Object.fromEntries(response.headers.entries()),
      data: responseData,
      latencyMs: Date.now() - start,
      method: method.toUpperCase(),
      url,
    };

    await logToolUsage('api_request', method, { url, status: response.status }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    await logToolUsage('api_request', method, { url }, userId, null, 'failed', Date.now() - start);
    return { success: false, error: error.message };
  }
}

