export async function apiDocument(action = 'generate', source, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    switch (action) {
      case 'generate': {
        if (!source) return { success: false, error: 'Source code or route definitions required' };
        // Parse Express routes from source code
        const routes = [];
        const routeRegex = /router\.(get|post|put|delete|patch)\s*\(\s*['"`]([^'"`]+)['"`]/gi;
        let match;
        while ((match = routeRegex.exec(source)) !== null) {
          routes.push({ method: match[1].toUpperCase(), path: match[2] });
        }

        const openApiSpec = {
          openapi: '3.0.3',
          info: { title: options.title || 'API Documentation', version: options.version || '1.0.0' },
          paths: {},
        };

        for (const route of routes) {
          if (!openApiSpec.paths[route.path]) openApiSpec.paths[route.path] = {};
          openApiSpec.paths[route.path][route.method.toLowerCase()] = {
            summary: `${route.method} ${route.path}`,
            responses: { '200': { description: 'Success' } },
          };
        }

        await logToolUsage('api_document', 'generate', { routeCount: routes.length }, userId, null, 'completed', Date.now() - start);
        return { success: true, action: 'generate', spec: openApiSpec, routesFound: routes.length };
      }
      case 'validate': {
        if (!source) return { success: false, error: 'OpenAPI spec required for validation' };
        const spec = typeof source === 'string' ? JSON.parse(source) : source;
        const errors = [];
        if (!spec.openapi) errors.push('Missing openapi version');
        if (!spec.info) errors.push('Missing info block');
        if (!spec.paths) errors.push('Missing paths');
        return { success: true, action: 'validate', valid: errors.length === 0, errors };
      }
      default:
        return { success: false, error: `Unknown document action: ${action}` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function apiTest(url, method = 'GET', expectations = {}, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!url) return { success: false, error: 'URL required for API testing' };

    const response = await fetch(url, {
      method: method.toUpperCase(),
      headers: {
        'Content-Type': 'application/json',
        'User-Agent': 'OnelastAI-APITest/2.0',
        ...(options.headers || {}),
      },
      body: options.body ? JSON.stringify(options.body) : undefined,
      signal: AbortSignal.timeout(options.timeout || 30000),
    });

    const contentType = response.headers.get('content-type') || '';
    let data;
    if (contentType.includes('json')) data = await response.json();
    else data = await response.text();

    const assertions = [];
    if (expectations.status) {
      assertions.push({ check: 'status', expected: expectations.status, actual: response.status, passed: response.status === expectations.status });
    }
    if (expectations.bodyContains) {
      const bodyStr = JSON.stringify(data);
      assertions.push({ check: 'bodyContains', expected: expectations.bodyContains, passed: bodyStr.includes(expectations.bodyContains) });
    }
    if (expectations.contentType) {
      assertions.push({ check: 'contentType', expected: expectations.contentType, passed: contentType.includes(expectations.contentType) });
    }
    if (expectations.maxLatency) {
      const latency = Date.now() - start;
      assertions.push({ check: 'maxLatency', expected: `${expectations.maxLatency}ms`, actual: `${latency}ms`, passed: latency <= expectations.maxLatency });
    }

    const allPassed = assertions.every(a => a.passed);

    await logToolUsage('api_test', method, { url, passed: allPassed }, userId, null, 'completed', Date.now() - start);
    return {
      success: true,
      url,
      method: method.toUpperCase(),
      status: response.status,
      latencyMs: Date.now() - start,
      assertions,
      allPassed,
      response: typeof data === 'string' ? data.slice(0, 2000) : data,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function apiTransform(action = 'rest_to_graphql', input, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    switch (action) {
      case 'rest_to_graphql': {
        if (!input) return { success: false, error: 'REST API definition required' };
        const endpoints = typeof input === 'string' ? JSON.parse(input) : input;

        let schema = 'type Query {\n';
        const types = new Set();

        for (const ep of (Array.isArray(endpoints) ? endpoints : [endpoints])) {
          const name = (ep.path || ep.name || 'unknown').replace(/[^a-zA-Z]/g, '_').replace(/^_+|_+$/g, '');
          if (ep.method === 'GET' || !ep.method) {
            schema += `  ${name}: ${name}Response\n`;
            types.add(name);
          }
        }
        schema += '}\n\n';

        for (const typeName of types) {
          schema += `type ${typeName}Response {\n  data: JSON\n  status: Int\n}\n\n`;
        }

        await logToolUsage('api_transform', action, {}, userId, null, 'completed', Date.now() - start);
        return { success: true, action, schema, typeCount: types.size };
      }
      case 'validate_schema': {
        const spec = typeof input === 'string' ? JSON.parse(input) : input;
        const errors = [];
        if (!spec) errors.push('Schema is empty');
        return { success: true, action, valid: errors.length === 0, errors };
      }
      default:
        return { success: false, error: `Unknown transform action: ${action}` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

