export async function sdkGenerate(spec, language = 'javascript', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!spec) return { success: false, error: 'API spec (OpenAPI JSON) required' };
    const apiSpec = typeof spec === 'string' ? JSON.parse(spec) : spec;
    const paths = apiSpec.paths || {};
    const className = options.className || 'ApiClient';

    let code = '';
    if (language === 'javascript' || language === 'typescript') {
      const isTs = language === 'typescript';
      code += `/**\n * Auto-generated SDK for ${apiSpec.info?.title || 'API'}\n * Version: ${apiSpec.info?.version || '1.0.0'}\n */\n\n`;
      code += `class ${className} {\n`;
      code += `  ${isTs ? 'private ' : ''}baseUrl${isTs ? ': string' : ''};\n`;
      code += `  ${isTs ? 'private ' : ''}headers${isTs ? ': Record<string, string>' : ''};\n\n`;
      code += `  constructor(baseUrl${isTs ? ': string' : ''}, apiKey${isTs ? '?: string' : ''}) {\n`;
      code += `    this.baseUrl = baseUrl;\n`;
      code += `    this.headers = { 'Content-Type': 'application/json', ...(apiKey ? { 'Authorization': \`Bearer \${apiKey}\` } : {}) };\n`;
      code += `  }\n\n`;

      for (const [path, methods] of Object.entries(paths)) {
        for (const [method, def] of Object.entries(methods)) {
          const fnName = (def.operationId || `${method}${path}`).replace(/[^a-zA-Z0-9]/g, '_').replace(/_+/g, '_');
          const hasBody = ['post', 'put', 'patch'].includes(method);
          code += `  async ${fnName}(${hasBody ? `body${isTs ? ': any' : ''}` : ''}${isTs ? `: Promise<any>` : ''}) {\n`;
          code += `    const res = await fetch(\`\${this.baseUrl}${path}\`, {\n`;
          code += `      method: '${method.toUpperCase()}',\n`;
          code += `      headers: this.headers,\n`;
          if (hasBody) code += `      body: JSON.stringify(body),\n`;
          code += `    });\n`;
          code += `    return res.json();\n`;
          code += `  }\n\n`;
        }
      }
      code += `}\n\nexport default ${className};\n`;
    } else if (language === 'python') {
      code += `"""Auto-generated SDK for ${apiSpec.info?.title || 'API'}"""\nimport requests\n\nclass ${className}:\n`;
      code += `    def __init__(self, base_url: str, api_key: str = None):\n`;
      code += `        self.base_url = base_url\n`;
      code += `        self.headers = {"Content-Type": "application/json"}\n`;
      code += `        if api_key:\n            self.headers["Authorization"] = f"Bearer {api_key}"\n\n`;

      for (const [path, methods] of Object.entries(paths)) {
        for (const [method, def] of Object.entries(methods)) {
          const fnName = (def.operationId || `${method}${path}`).replace(/[^a-zA-Z0-9]/g, '_').replace(/_+/g, '_');
          const hasBody = ['post', 'put', 'patch'].includes(method);
          code += `    def ${fnName}(self${hasBody ? ', body: dict = None' : ''}):\n`;
          code += `        return requests.${method}(f"{self.base_url}${path}", headers=self.headers${hasBody ? ', json=body' : ''}).json()\n\n`;
        }
      }
    }

    await logToolUsage('sdk_generate', language, { paths: Object.keys(paths).length }, userId, null, 'completed', Date.now() - start);
    return {
      success: true,
      language,
      code,
      className,
      endpointCount: Object.keys(paths).length,
      sizeBytes: code.length,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

// ─── BONUS API & Integrations (3 NEW) ───

export async function apiValidate(action = 'spec', input, schema, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Input required for validation' };
    const parsed = typeof input === 'string' ? JSON.parse(input) : input;

    switch (action) {
      case 'spec': {
        // Validate OpenAPI spec structure
        const errors = [];
        if (!parsed.openapi && !parsed.swagger) errors.push('Missing openapi/swagger version field');
        if (!parsed.info) errors.push('Missing info block');
        if (!parsed.info?.title) errors.push('Missing info.title');
        if (!parsed.info?.version) errors.push('Missing info.version');
        if (!parsed.paths && !parsed.webhooks) errors.push('Missing paths block');
        if (parsed.paths) {
          for (const [p, methods] of Object.entries(parsed.paths)) {
            if (!p.startsWith('/')) errors.push(`Path "${p}" must start with /`);
            for (const [m, def] of Object.entries(methods)) {
              if (!['get','post','put','delete','patch','head','options','trace'].includes(m)) continue;
              if (!def.responses) errors.push(`${m.toUpperCase()} ${p}: missing responses`);
            }
          }
        }
        await logToolUsage('api_validate', action, { errors: errors.length }, userId, null, 'completed', Date.now() - start);
        return { success: true, action, valid: errors.length === 0, errors, pathCount: parsed.paths ? Object.keys(parsed.paths).length : 0 };
      }
      case 'schema': {
        // Basic JSON Schema validation
        const errors = [];
        if (!parsed.type) errors.push('Missing root type');
        if (parsed.type === 'object' && !parsed.properties) errors.push('Object type missing properties');
        if (parsed.type === 'array' && !parsed.items) errors.push('Array type missing items');
        if (parsed.required && !Array.isArray(parsed.required)) errors.push('required must be an array');
        if (parsed.required && parsed.properties) {
          for (const req of parsed.required) {
            if (!parsed.properties[req]) errors.push(`Required field "${req}" not in properties`);
          }
        }
        return { success: true, action, valid: errors.length === 0, errors };
      }
      case 'request':
      case 'response': {
        // Validate payload against a JSON Schema
        if (!schema) return { success: false, error: 'Schema required for request/response validation' };
        const schemaParsed = typeof schema === 'string' ? JSON.parse(schema) : schema;
        const errors = [];
        if (schemaParsed.required && schemaParsed.properties) {
          for (const req of schemaParsed.required) {
            if (parsed[req] === undefined) errors.push(`Missing required field: ${req}`);
          }
        }
        if (schemaParsed.properties) {
          for (const [key, def] of Object.entries(schemaParsed.properties)) {
            if (parsed[key] !== undefined && def.type) {
              const actual = Array.isArray(parsed[key]) ? 'array' : typeof parsed[key];
              if (def.type === 'integer' && (typeof parsed[key] !== 'number' || !Number.isInteger(parsed[key]))) {
                errors.push(`${key}: expected integer, got ${actual}`);
              } else if (def.type !== 'integer' && actual !== def.type) {
                errors.push(`${key}: expected ${def.type}, got ${actual}`);
              }
            }
          }
        }
        return { success: true, action, valid: errors.length === 0, errors, fieldsChecked: Object.keys(parsed).length };
      }
      case 'contract': {
        // Validate that a response matches its spec endpoint contract
        const errors = [];
        if (!parsed.endpoint) errors.push('Missing endpoint field');
        if (!parsed.spec) errors.push('Missing spec field');
        if (!parsed.response) errors.push('Missing response field');
        return { success: true, action, valid: errors.length === 0, errors };
      }
      default:
        return { success: false, error: `Unknown validate action: ${action}` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function apiProxy(action = 'forward', url, method = 'GET', headers = {}, body = null, proxyConfig = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!url) return { success: false, error: 'URL required' };

    switch (action) {
      case 'forward': {
        // Simple forward with optional header rewrite
        const fwdHeaders = { 'User-Agent': 'OnelastAI-Proxy/2.0', ...headers };
        if (proxyConfig.rewriteHeaders) {
          Object.assign(fwdHeaders, proxyConfig.rewriteHeaders);
        }
        const fetchOpts = {
          method: method.toUpperCase(),
          headers: fwdHeaders,
          signal: AbortSignal.timeout(proxyConfig.timeout || 30000),
        };
        if (body && !['GET', 'HEAD'].includes(method.toUpperCase())) {
          fetchOpts.body = typeof body === 'string' ? body : JSON.stringify(body);
          if (!fwdHeaders['Content-Type']) fwdHeaders['Content-Type'] = 'application/json';
        }
        const res = await fetch(url, fetchOpts);
        const ct = res.headers.get('content-type') || '';
        let data = ct.includes('json') ? await res.json() : await res.text();
        if (typeof data === 'string' && data.length > 10000) data = data.slice(0, 10000) + '...[truncated]';
        await logToolUsage('api_proxy', action, { url, status: res.status }, userId, null, 'completed', Date.now() - start);
        return { success: true, action, status: res.status, headers: Object.fromEntries(res.headers.entries()), data, latencyMs: Date.now() - start };
      }
      case 'delay': {
        // Inject artificial latency before forwarding
        const delayMs = proxyConfig.addLatencyMs || 1000;
        await new Promise(r => setTimeout(r, Math.min(delayMs, 10000)));
        const res = await fetch(url, { method: method.toUpperCase(), headers, signal: AbortSignal.timeout(30000) });
        const data = await res.text();
        return { success: true, action, status: res.status, addedLatencyMs: delayMs, totalLatencyMs: Date.now() - start, data: data.slice(0, 5000) };
      }
      case 'throttle': {
        // Simulate rate limiting
        const rps = proxyConfig.rateLimitRps || 10;
        const simulated = Math.random() > (1 / rps) ? 'allowed' : 'rate_limited';
        if (simulated === 'rate_limited') {
          return { success: true, action, status: 429, message: `Simulated rate limit (${rps} rps)`, rateLimited: true };
        }
        const res = await fetch(url, { method: method.toUpperCase(), headers, signal: AbortSignal.timeout(30000) });
        const data = await res.text();
        return { success: true, action, status: res.status, rateLimited: false, rpsLimit: rps, data: data.slice(0, 5000), latencyMs: Date.now() - start };
      }
      case 'mirror': {
        // Mirror request to two URLs and compare
        const mirrorUrl = proxyConfig.mirrorUrl;
        if (!mirrorUrl) return { success: false, error: 'mirrorUrl required in proxyConfig' };
        const [r1, r2] = await Promise.allSettled([
          fetch(url, { method: method.toUpperCase(), headers, signal: AbortSignal.timeout(15000) }),
          fetch(mirrorUrl, { method: method.toUpperCase(), headers, signal: AbortSignal.timeout(15000) }),
        ]);
        return {
          success: true, action,
          primary: { status: r1.status === 'fulfilled' ? r1.value.status : 'error', ok: r1.status === 'fulfilled' },
          mirror: { status: r2.status === 'fulfilled' ? r2.value.status : 'error', ok: r2.status === 'fulfilled' },
          match: r1.status === 'fulfilled' && r2.status === 'fulfilled' && r1.value.status === r2.value.status,
        };
      }
      default:
        return { success: false, error: `Unknown proxy action: ${action}` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function apiDiff(action = 'spec', before, after, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!before || !after) return { success: false, error: 'Both before and after required' };
    const b = typeof before === 'string' ? JSON.parse(before) : before;
    const a = typeof after === 'string' ? JSON.parse(after) : after;

    function deepDiff(obj1, obj2, path = '') {
      const changes = [];
      const allKeys = new Set([...Object.keys(obj1 || {}), ...Object.keys(obj2 || {})]);
      for (const key of allKeys) {
        const fullPath = path ? `${path}.${key}` : key;
        const v1 = obj1?.[key];
        const v2 = obj2?.[key];
        if (v1 === undefined && v2 !== undefined) {
          changes.push({ type: 'added', path: fullPath, value: v2 });
        } else if (v1 !== undefined && v2 === undefined) {
          changes.push({ type: 'removed', path: fullPath, value: v1 });
        } else if (typeof v1 === 'object' && typeof v2 === 'object' && v1 !== null && v2 !== null && !Array.isArray(v1)) {
          changes.push(...deepDiff(v1, v2, fullPath));
        } else if (JSON.stringify(v1) !== JSON.stringify(v2)) {
          changes.push({ type: 'changed', path: fullPath, before: v1, after: v2 });
        }
      }
      return changes;
    }

    switch (action) {
      case 'spec': {
        // Compare two OpenAPI specs
        const pathsBefore = Object.keys(b.paths || {});
        const pathsAfter = Object.keys(a.paths || {});
        const added = pathsAfter.filter(p => !pathsBefore.includes(p));
        const removed = pathsBefore.filter(p => !pathsAfter.includes(p));
        const common = pathsBefore.filter(p => pathsAfter.includes(p));
        const methodChanges = [];
        for (const p of common) {
          const mbBefore = Object.keys(b.paths[p]).filter(m => ['get','post','put','delete','patch'].includes(m));
          const mbAfter = Object.keys(a.paths[p]).filter(m => ['get','post','put','delete','patch'].includes(m));
          const addedMethods = mbAfter.filter(m => !mbBefore.includes(m));
          const removedMethods = mbBefore.filter(m => !mbAfter.includes(m));
          if (addedMethods.length || removedMethods.length) {
            methodChanges.push({ path: p, addedMethods, removedMethods });
          }
        }
        const breaking = removed.length > 0 || methodChanges.some(mc => mc.removedMethods.length > 0);
        await logToolUsage('api_diff', action, { added: added.length, removed: removed.length, breaking }, userId, null, 'completed', Date.now() - start);
        return { success: true, action, addedEndpoints: added, removedEndpoints: removed, methodChanges, breaking, totalBefore: pathsBefore.length, totalAfter: pathsAfter.length };
      }
      case 'response': {
        // Deep diff two API responses
        const changes = deepDiff(b, a);
        const breaking = changes.some(c => c.type === 'removed');
        return { success: true, action, changes, changeCount: changes.length, breaking };
      }
      case 'schema': {
        // Compare two JSON schemas
        const changes = deepDiff(b, a);
        return { success: true, action, changes, changeCount: changes.length };
      }
      case 'endpoints': {
        // Simple endpoint list comparison
        const beforeList = Array.isArray(b) ? b : Object.keys(b);
        const afterList = Array.isArray(a) ? a : Object.keys(a);
        const added = afterList.filter(e => !beforeList.includes(e));
        const removed = beforeList.filter(e => !afterList.includes(e));
        return { success: true, action, added, removed, unchanged: beforeList.filter(e => afterList.includes(e)).length, breaking: removed.length > 0 };
      }
      default:
        return { success: false, error: `Unknown diff action: ${action}` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

