export async function cryptoHash(input, algorithm = 'sha256', encoding = 'hex', userId = 'default') {
  const start = Date.now();
  try {
    const crypto = await import('crypto');
    if (!input) return { success: false, error: 'Input required for hashing' };

    const supported = ['sha256', 'sha512', 'sha1', 'md5', 'sha384', 'sha3-256', 'sha3-512'];
    if (algorithm === 'bcrypt') {
      // bcrypt requires special handling
      const bcryptHash = crypto.createHash('sha256').update(input + Date.now()).digest('hex');
      await logToolUsage('crypto_hash', 'bcrypt', {}, userId, null, 'completed', Date.now() - start);
      return {
        success: true,
        algorithm: 'sha256-simulated-bcrypt',
        hash: bcryptHash,
        note: 'For real bcrypt, use the bcryptjs library. This is a SHA-256 hash.',
      };
    }

    if (!supported.includes(algorithm)) {
      return { success: false, error: `Unsupported algorithm. Supported: ${supported.join(', ')}, bcrypt` };
    }

    const hash = crypto.createHash(algorithm).update(input).digest(encoding);
    const result = {
      success: true,
      algorithm,
      encoding,
      hash,
      inputLength: input.length,
      hashLength: hash.length,
    };

    // Compare mode
    if (arguments[4]) {
      result.match = hash === arguments[4];
    }

    await logToolUsage('crypto_hash', algorithm, { inputLength: input.length }, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function cryptoEncrypt(action = 'encrypt', data, key, algorithm = 'aes-256-gcm', userId = 'default') {
  const start = Date.now();
  try {
    const crypto = await import('crypto');
    if (!data) return { success: false, error: 'Data required' };

    if (action === 'encrypt') {
      const encKey = key ? Buffer.from(key, 'hex') : crypto.randomBytes(32);
      const iv = crypto.randomBytes(algorithm.includes('gcm') ? 12 : 16);
      const cipher = crypto.createCipheriv(algorithm, encKey, iv);
      let encrypted = cipher.update(data, 'utf8', 'hex');
      encrypted += cipher.final('hex');

      const result = {
        success: true,
        action: 'encrypt',
        algorithm,
        encrypted,
        iv: iv.toString('hex'),
        key: encKey.toString('hex'),
      };

      if (algorithm.includes('gcm')) {
        result.authTag = cipher.getAuthTag().toString('hex');
      }

      await logToolUsage('crypto_encrypt', 'encrypt', { algorithm }, userId, null, 'completed', Date.now() - start);
      return result;
    }

    if (action === 'decrypt') {
      if (!key) return { success: false, error: 'Decryption key required' };
      const options = typeof arguments[5] === 'object' ? arguments[5] : {};
      const iv = Buffer.from(options.iv || '', 'hex');
      const decipher = crypto.createDecipheriv(algorithm, Buffer.from(key, 'hex'), iv);
      if (algorithm.includes('gcm') && options.authTag) {
        decipher.setAuthTag(Buffer.from(options.authTag, 'hex'));
      }
      let decrypted = decipher.update(data, 'hex', 'utf8');
      decrypted += decipher.final('utf8');

      await logToolUsage('crypto_encrypt', 'decrypt', { algorithm }, userId, null, 'completed', Date.now() - start);
      return { success: true, action: 'decrypt', decrypted, algorithm };
    }

    return { success: false, error: 'Action must be encrypt or decrypt' };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function cryptoSign(action = 'sign', data, key, algorithm = 'sha256', userId = 'default') {
  const start = Date.now();
  try {
    const crypto = await import('crypto');
    if (!data) return { success: false, error: 'Data required for signing' };

    if (action === 'sign') {
      if (key && key.includes('BEGIN')) {
        // RSA/EC signing with private key
        const sign = crypto.createSign(algorithm);
        sign.update(data);
        const signature = sign.sign(key, 'hex');
        await logToolUsage('crypto_sign', 'sign-rsa', {}, userId, null, 'completed', Date.now() - start);
        return { success: true, action: 'sign', algorithm, signature, type: 'asymmetric' };
      }

      // HMAC signing
      const hmacKey = key || crypto.randomBytes(32).toString('hex');
      const signature = crypto.createHmac(algorithm, hmacKey).update(data).digest('hex');
      await logToolUsage('crypto_sign', 'sign-hmac', {}, userId, null, 'completed', Date.now() - start);
      return { success: true, action: 'sign', algorithm, signature, key: hmacKey, type: 'hmac' };
    }

    if (action === 'verify') {
      if (!key) return { success: false, error: 'Key/signature required for verification' };
      const options = typeof arguments[5] === 'object' ? arguments[5] : {};

      if (key.includes('BEGIN')) {
        const verify = crypto.createVerify(algorithm);
        verify.update(data);
        const valid = verify.verify(key, options.signature || '', 'hex');
        return { success: true, action: 'verify', valid, type: 'asymmetric' };
      }

      // HMAC verify
      const expected = crypto.createHmac(algorithm, key).update(data).digest('hex');
      const valid = expected === (options.signature || '');
      return { success: true, action: 'verify', valid, type: 'hmac' };
    }

    if (action === 'generate_keypair') {
      const { publicKey, privateKey } = crypto.generateKeyPairSync('rsa', {
        modulusLength: 2048,
        publicKeyEncoding: { type: 'spki', format: 'pem' },
        privateKeyEncoding: { type: 'pkcs8', format: 'pem' },
      });
      await logToolUsage('crypto_sign', 'keygen', {}, userId, null, 'completed', Date.now() - start);
      return { success: true, action: 'generate_keypair', publicKey, privateKey, algorithm: 'RSA-2048' };
    }

    return { success: false, error: `Unknown sign action: ${action}` };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function scanSecrets(content, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!content) return { success: false, error: 'Content to scan is required' };

    const patterns = [
      { name: 'AWS Access Key', regex: /AKIA[0-9A-Z]{16}/g },
      { name: 'AWS Secret Key', regex: /(?:aws_secret_access_key|secret_key)\s*[=:]\s*['"]?([A-Za-z0-9/+=]{40})/gi },
      { name: 'GitHub Token', regex: /gh[pous]_[A-Za-z0-9_]{36,}/g },
      { name: 'OpenAI API Key', regex: /sk-[A-Za-z0-9]{20,}/g },
      { name: 'Stripe Key', regex: /[sr]k_(test|live)_[A-Za-z0-9]{20,}/g },
      { name: 'JWT Token', regex: /eyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}/g },
      { name: 'Generic API Key', regex: /(?:api[_-]?key|apikey|api[_-]?secret)\s*[=:]\s*['"]?([A-Za-z0-9_-]{20,})/gi },
      { name: 'Private Key', regex: /-----BEGIN (?:RSA |EC )?PRIVATE KEY-----/g },
      { name: 'Database URL', regex: /(?:postgres|mysql|mongodb):\/\/[^\s'"]+/gi },
      { name: 'Slack Token', regex: /xox[baprs]-[A-Za-z0-9-]{10,}/g },
      { name: 'Google API Key', regex: /AIza[0-9A-Za-z_-]{35}/g },
      { name: 'Twilio Key', regex: /SK[0-9a-fA-F]{32}/g },
      { name: 'SendGrid Key', regex: /SG\.[A-Za-z0-9_-]{22,}\.[A-Za-z0-9_-]{43,}/g },
      { name: 'Password in URL', regex: /[a-zA-Z]+:\/\/[^:]+:[^@]+@/g },
    ];

    const findings = [];
    for (const pat of patterns) {
      const matches = content.match(pat.regex);
      if (matches) {
        for (const match of matches) {
          findings.push({
            type: pat.name,
            severity: 'high',
            match: match.slice(0, 8) + '***' + match.slice(-4),
            length: match.length,
          });
        }
      }
    }

    // Store scan result in DB
    await prisma.toolUsage.create({
      data: {
        toolName: 'scan_secrets',
        command: 'scan',
        arguments: { findingsCount: findings.length, contentLength: content.length },
        userId: userId || undefined,
        status: 'completed',
        latencyMs: Date.now() - start,
        occurredAt: new Date(),
      },
    });

    return {
      success: true,
      findings,
      totalSecrets: findings.length,
      severity: findings.length > 0 ? 'high' : 'clean',
      scannedBytes: content.length,
      message: findings.length > 0
        ? `⚠️ Found ${findings.length} potential secret(s)! Review and rotate immediately.`
        : '✅ No secrets detected in the scanned content.',
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function scanMalware(file, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!file) return { success: false, error: 'File path or content required' };

    const suspiciousPatterns = [
      { name: 'eval()', pattern: /eval\s*\(/g, severity: 'high' },
      { name: 'Function constructor', pattern: /new\s+Function\s*\(/g, severity: 'high' },
      { name: 'Base64 decode + eval', pattern: /atob\s*\(.*eval/g, severity: 'critical' },
      { name: 'document.write', pattern: /document\.write\s*\(/g, severity: 'medium' },
      { name: 'iframe injection', pattern: /<iframe[^>]+src/gi, severity: 'high' },
      { name: 'Obfuscated code', pattern: /\\x[0-9a-fA-F]{2}/g, severity: 'medium' },
      { name: 'Shell exec', pattern: /exec\s*\(\s*['"`](?:bash|sh|cmd|powershell)/gi, severity: 'critical' },
      { name: 'Crypto mining', pattern: /(?:coinhive|cryptonight|minergate|coin-hive)/gi, severity: 'critical' },
      { name: 'Data exfiltration', pattern: /(?:fetch|XMLHttpRequest|sendBeacon)\s*\([^)]*(?:cookie|localStorage|sessionStorage)/gi, severity: 'high' },
    ];

    let content = file;
    if (typeof file === 'string' && file.length < 500 && !file.includes('\n')) {
      // Might be a file path
      try {
        content = fs.readFileSync(file, 'utf-8');
      } catch { /* use file as content */ }
    }

    const findings = [];
    for (const pat of suspiciousPatterns) {
      const matches = content.match(pat.pattern);
      if (matches) {
        findings.push({
          name: pat.name,
          severity: pat.severity,
          occurrences: matches.length,
        });
      }
    }

    const severityScore = findings.reduce((score, f) => {
      if (f.severity === 'critical') return score + 10 * f.occurrences;
      if (f.severity === 'high') return score + 5 * f.occurrences;
      return score + 2 * f.occurrences;
    }, 0);

    await logToolUsage('scan_malware', 'scan', { findingsCount: findings.length, severityScore }, userId, null, 'completed', Date.now() - start);

    return {
      success: true,
      findings,
      totalIssues: findings.length,
      severityScore,
      risk: severityScore === 0 ? 'clean' : severityScore < 10 ? 'low' : severityScore < 30 ? 'medium' : 'high',
      scannedBytes: content.length,
      message: findings.length === 0
        ? '✅ No malware patterns detected.'
        : `⚠️ Found ${findings.length} suspicious pattern(s). Severity score: ${severityScore}`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function authGenerate(type = 'jwt', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    const crypto = await import('crypto');

    switch (type) {
      case 'jwt': {
        const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64url');
        const payload = Buffer.from(JSON.stringify({
          sub: options.subject || userId || 'user',
          iss: options.issuer || 'mumtazai',
          iat: Math.floor(Date.now() / 1000),
          exp: Math.floor(Date.now() / 1000) + (options.expiresIn || 3600),
          ...options.claims,
        })).toString('base64url');

        const secret = options.secret || crypto.randomBytes(32).toString('hex');
        const signature = crypto.createHmac('sha256', secret).update(`${header}.${payload}`).digest('base64url');

        await logToolUsage('auth_generate', 'jwt', {}, userId, null, 'completed', Date.now() - start);
        return {
          success: true,
          type: 'jwt',
          token: `${header}.${payload}.${signature}`,
          secret,
          expiresIn: options.expiresIn || 3600,
        };
      }
      case 'api_key': {
        const prefix = options.prefix || 'sk';
        const key = `${prefix}_${crypto.randomBytes(32).toString('hex')}`;
        await logToolUsage('auth_generate', 'api_key', {}, userId, null, 'completed', Date.now() - start);
        return { success: true, type: 'api_key', key, prefix };
      }
      case 'oauth_token': {
        const token = crypto.randomBytes(40).toString('hex');
        const refreshToken = crypto.randomBytes(40).toString('hex');
        await logToolUsage('auth_generate', 'oauth', {}, userId, null, 'completed', Date.now() - start);
        return {
          success: true,
          type: 'oauth',
          access_token: token,
          refresh_token: refreshToken,
          token_type: 'Bearer',
          expires_in: options.expiresIn || 3600,
        };
      }
      case 'uuid': {
        const uuid = crypto.randomUUID();
        return { success: true, type: 'uuid', value: uuid };
      }
      case 'random': {
        const length = options.length || 32;
        const value = crypto.randomBytes(length).toString(options.encoding || 'hex');
        return { success: true, type: 'random', value, length };
      }
      default:
        return { success: false, error: `Unknown auth type: ${type}. Use jwt, api_key, oauth_token, uuid, random.` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

