export async function fileWatch(action = 'watch', filePath, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    switch (action) {
      case 'watch': {
        if (!filePath) return { success: false, error: 'File path required' };

        // Store watch registration in DB
        await prisma.toolUsage.create({
          data: {
            toolName: 'file_watch',
            command: 'watch',
            arguments: {
              filePath,
              events: options.events || ['change', 'rename'],
              recursive: options.recursive || false,
              registeredAt: new Date().toISOString(),
            },
            inputPreview: filePath,
            userId: userId || undefined,
            status: 'completed',
            latencyMs: Date.now() - start,
            occurredAt: new Date(),
          },
        });

        // Check current file state
        let stats = null;
        try {
          const fstat = fs.statSync(filePath);
          stats = {
            size: fstat.size,
            modified: fstat.mtime.toISOString(),
            created: fstat.birthtime.toISOString(),
            isDirectory: fstat.isDirectory(),
          };
        } catch { /* file may not exist */ }

        return {
          success: true,
          action: 'watch',
          filePath,
          currentState: stats,
          message: `File watch registered for ${filePath}. Events will be logged to database.`,
        };
      }
      case 'check': {
        if (!filePath) return { success: false, error: 'File path required' };
        try {
          const fstat = fs.statSync(filePath);
          return {
            success: true,
            action: 'check',
            filePath,
            exists: true,
            size: fstat.size,
            modified: fstat.mtime.toISOString(),
            created: fstat.birthtime.toISOString(),
            isDirectory: fstat.isDirectory(),
          };
        } catch (e) {
          return { success: true, action: 'check', filePath, exists: false, error: e.message };
        }
      }
      case 'list': {
        const watches = await prisma.toolUsage.findMany({
          where: { toolName: 'file_watch', command: 'watch', userId: userId || undefined },
          orderBy: { occurredAt: 'desc' },
          take: 50,
        });
        return { success: true, action: 'list', watches: watches.map(w => w.arguments), count: watches.length };
      }
      default:
        return { success: false, error: `Unknown watch action: ${action}` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function syncFiles(action = 'compare', source, destination, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    switch (action) {
      case 'compare': {
        if (!source || !destination) return { success: false, error: 'Source and destination paths required' };

        const getFiles = (dir) => {
          const results = [];
          try {
            const items = fs.readdirSync(dir, { withFileTypes: true });
            for (const item of items) {
              const fullPath = path.join(dir, item.name);
              if (item.isFile()) {
                const stat = fs.statSync(fullPath);
                results.push({ name: item.name, path: fullPath, size: stat.size, modified: stat.mtime.toISOString() });
              } else if (item.isDirectory() && options.recursive !== false) {
                results.push(...getFiles(fullPath));
              }
            }
          } catch { /* skip unreadable dirs */ }
          return results;
        };

        const sourceFiles = getFiles(source);
        const destFiles = getFiles(destination);
        const destMap = new Map(destFiles.map(f => [path.relative(destination, f.path), f]));

        const diff = {
          onlyInSource: [],
          onlyInDest: [],
          modified: [],
          identical: [],
        };

        for (const sf of sourceFiles) {
          const relPath = path.relative(source, sf.path);
          const df = destMap.get(relPath);
          if (!df) diff.onlyInSource.push(relPath);
          else if (sf.size !== df.size || sf.modified !== df.modified) diff.modified.push(relPath);
          else diff.identical.push(relPath);
          destMap.delete(relPath);
        }
        diff.onlyInDest = Array.from(destMap.keys());

        await logToolUsage('sync_files', 'compare', { source, destination }, userId, null, 'completed', Date.now() - start);
        return { success: true, action: 'compare', source, destination, diff, summary: {
          onlyInSource: diff.onlyInSource.length,
          onlyInDest: diff.onlyInDest.length,
          modified: diff.modified.length,
          identical: diff.identical.length,
        }};
      }
      case 'sync': {
        if (!source || !destination) return { success: false, error: 'Source and destination paths required' };
        // Use the compare result and copy
        const compareResult = await syncFiles('compare', source, destination, options, userId);
        if (!compareResult.success) return compareResult;

        let copied = 0;
        for (const file of [...compareResult.diff.onlyInSource, ...compareResult.diff.modified]) {
          const srcPath = path.join(source, file);
          const destPath = path.join(destination, file);
          try {
            fs.mkdirSync(path.dirname(destPath), { recursive: true });
            fs.copyFileSync(srcPath, destPath);
            copied++;
          } catch { /* skip errors */ }
        }

        await logToolUsage('sync_files', 'sync', { copied }, userId, null, 'completed', Date.now() - start);
        return { success: true, action: 'sync', filesCopied: copied, diff: compareResult.diff };
      }
      default:
        return { success: false, error: `Unknown sync action: ${action}` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

// ─── CONTENT & MARKDOWN (5 NEW) ───

export async function markdownConvert(input, format = 'html', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Markdown input required' };

    let output = '';
    if (format === 'html') {
      // Basic markdown → HTML conversion
      output = input
        .replace(/^### (.+)$/gm, '<h3>$1</h3>')
        .replace(/^## (.+)$/gm, '<h2>$1</h2>')
        .replace(/^# (.+)$/gm, '<h1>$1</h1>')
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        .replace(/\*(.+?)\*/g, '<em>$1</em>')
        .replace(/`(.+?)`/g, '<code>$1</code>')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
        .replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
        .replace(/^- (.+)$/gm, '<li>$1</li>')
        .replace(/^(\d+)\. (.+)$/gm, '<li>$2</li>')
        .replace(/^> (.+)$/gm, '<blockquote>$1</blockquote>')
        .replace(/^---$/gm, '<hr />')
        .replace(/\n\n/g, '</p><p>')
        .replace(/^/, '<p>')
        .replace(/$/, '</p>');
    } else if (format === 'text') {
      output = input
        .replace(/^#{1,6}\s+/gm, '')
        .replace(/\*\*(.+?)\*\*/g, '$1')
        .replace(/\*(.+?)\*/g, '$1')
        .replace(/`(.+?)`/g, '$1')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1 ($2)')
        .replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '[Image: $1]')
        .replace(/^[-*] /gm, '• ')
        .replace(/^> /gm, '  ');
    } else if (format === 'latex') {
      output = input
        .replace(/^# (.+)$/gm, '\\section{$1}')
        .replace(/^## (.+)$/gm, '\\subsection{$1}')
        .replace(/^### (.+)$/gm, '\\subsubsection{$1}')
        .replace(/\*\*(.+?)\*\*/g, '\\textbf{$1}')
        .replace(/\*(.+?)\*/g, '\\textit{$1}')
        .replace(/`(.+?)`/g, '\\texttt{$1}');
    }

    await logToolUsage('markdown_convert', format, { inputLength: input.length }, userId, null, 'completed', Date.now() - start);
    return { success: true, format, output, inputLength: input.length, outputLength: output.length };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function markdownValidate(input, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Markdown input required' };

    const lines = input.split('\n');
    const issues = [];

    // Check headings
    let prevLevel = 0;
    for (let i = 0; i < lines.length; i++) {
      const hMatch = lines[i].match(/^(#{1,6})\s/);
      if (hMatch) {
        const level = hMatch[1].length;
        if (level > prevLevel + 1 && prevLevel > 0) {
          issues.push({ line: i + 1, severity: 'warning', message: `Heading level skipped from h${prevLevel} to h${level}` });
        }
        prevLevel = level;
      }
    }

    // Check links
    const linkRegex = /\[([^\]]*)\]\(([^)]+)\)/g;
    let m;
    while ((m = linkRegex.exec(input)) !== null) {
      if (!m[1]) issues.push({ line: 0, severity: 'warning', message: `Empty link text for: ${m[2]}` });
      if (m[2].startsWith('http') && !m[2].match(/^https?:\/\/.+/)) {
        issues.push({ line: 0, severity: 'error', message: `Invalid URL: ${m[2]}` });
      }
    }

    // Check code blocks
    const codeBlockCount = (input.match(/```/g) || []).length;
    if (codeBlockCount % 2 !== 0) {
      issues.push({ severity: 'error', message: 'Unclosed code block (odd number of ``` markers)' });
    }

    // Check frontmatter
    if (lines[0] === '---') {
      const endIdx = lines.indexOf('---', 1);
      if (endIdx < 0) issues.push({ severity: 'error', message: 'Unclosed frontmatter (missing closing ---)' });
    }

    await logToolUsage('markdown_validate', 'validate', { issueCount: issues.length }, userId, null, 'completed', Date.now() - start);
    return {
      success: true,
      valid: issues.filter(i => i.severity === 'error').length === 0,
      issues,
      stats: {
        lines: lines.length,
        words: input.split(/\s+/).filter(Boolean).length,
        headings: (input.match(/^#{1,6}\s/gm) || []).length,
        links: (input.match(/\[([^\]]*)\]\(([^)]+)\)/g) || []).length,
        codeBlocks: codeBlockCount / 2,
      },
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function markdownGenerate(template = 'readme', data = {}, userId = 'default') {
  const start = Date.now();
  try {
    let output = '';

    switch (template) {
      case 'readme':
        output = `# ${data.title || 'Project Name'}\n\n`;
        output += `${data.description || 'A brief description of the project.'}\n\n`;
        output += `## Installation\n\n\`\`\`bash\nnpm install ${data.package || 'package-name'}\n\`\`\`\n\n`;
        output += `## Usage\n\n\`\`\`${data.language || 'javascript'}\n${data.example || '// Add usage example'}\n\`\`\`\n\n`;
        output += `## Features\n\n${(data.features || ['Feature 1', 'Feature 2']).map(f => `- ${f}`).join('\n')}\n\n`;
        output += `## License\n\n${data.license || 'MIT'}\n`;
        break;
      case 'changelog':
        output = `# Changelog\n\n## [${data.version || '1.0.0'}] - ${new Date().toISOString().split('T')[0]}\n\n`;
        output += `### Added\n${(data.added || ['Initial release']).map(a => `- ${a}`).join('\n')}\n\n`;
        if (data.changed) output += `### Changed\n${data.changed.map(c => `- ${c}`).join('\n')}\n\n`;
        if (data.fixed) output += `### Fixed\n${data.fixed.map(f => `- ${f}`).join('\n')}\n\n`;
        break;
      case 'api':
        output = `# API Documentation\n\n`;
        for (const ep of (data.endpoints || [{ method: 'GET', path: '/api/example', description: 'Example endpoint' }])) {
          output += `## \`${ep.method}\` ${ep.path}\n\n${ep.description || ''}\n\n`;
          if (ep.params) output += `### Parameters\n\n| Name | Type | Required | Description |\n|------|------|----------|-------------|\n${ep.params.map(p => `| ${p.name} | ${p.type} | ${p.required ? 'Yes' : 'No'} | ${p.description} |`).join('\n')}\n\n`;
        }
        break;
      case 'contributing':
        output = `# Contributing to ${data.project || 'Project'}\n\n`;
        output += `## How to Contribute\n\n1. Fork the repository\n2. Create your feature branch (\`git checkout -b feature/amazing-feature\`)\n3. Commit your changes (\`git commit -m 'Add amazing feature'\`)\n4. Push to the branch (\`git push origin feature/amazing-feature\`)\n5. Open a Pull Request\n\n`;
        output += `## Code of Conduct\n\nPlease be respectful and constructive.\n`;
        break;
      default:
        output = `# ${data.title || template}\n\n${data.content || 'Add content here.'}\n`;
    }

    await logToolUsage('markdown_generate', template, {}, userId, null, 'completed', Date.now() - start);
    return { success: true, template, output, length: output.length };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function markdownToc(input, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Markdown input required' };

    const lines = input.split('\n');
    const headings = [];
    let inCodeBlock = false;

    for (const line of lines) {
      if (line.startsWith('```')) { inCodeBlock = !inCodeBlock; continue; }
      if (inCodeBlock) continue;

      const match = line.match(/^(#{1,6})\s+(.+)/);
      if (match) {
        const level = match[1].length;
        const text = match[2].replace(/\*\*|__|\*|_|`/g, '');
        const anchor = text.toLowerCase().replace(/[^\w\s-]/g, '').replace(/\s+/g, '-');
        if (level >= (options.minLevel || 1) && level <= (options.maxLevel || 4)) {
          headings.push({ level, text, anchor });
        }
      }
    }

    const toc = headings.map(h => {
      const indent = '  '.repeat(h.level - (options.minLevel || 1));
      return `${indent}- [${h.text}](#${h.anchor})`;
    }).join('\n');

    await logToolUsage('markdown_toc', 'generate', { headingCount: headings.length }, userId, null, 'completed', Date.now() - start);
    return { success: true, toc, headings, headingCount: headings.length };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function markdownFormat(input, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Markdown input required' };

    let output = input;

    // Normalize line endings
    output = output.replace(/\r\n/g, '\n');

    // Ensure single blank line between sections
    output = output.replace(/\n{3,}/g, '\n\n');

    // Ensure space after heading markers
    output = output.replace(/^(#{1,6})([^ #\n])/gm, '$1 $2');

    // Ensure list items have space after marker
    output = output.replace(/^([-*+])([^ \n])/gm, '$1 $2');
    output = output.replace(/^(\d+\.)([^ \n])/gm, '$1 $2');

    // Trim trailing whitespace
    output = output.replace(/[ \t]+$/gm, '');

    // Ensure file ends with newline
    if (!output.endsWith('\n')) output += '\n';

    // Ensure blank line before headings
    output = output.replace(/([^\n])\n(#{1,6}\s)/g, '$1\n\n$2');

    const changes = [];
    if (output !== input) {
      if (input.includes('\r\n')) changes.push('Normalized line endings');
      if (/\n{3,}/.test(input)) changes.push('Removed extra blank lines');
      if (/^#{1,6}[^ #\n]/m.test(input)) changes.push('Added space after heading markers');
      if (/[ \t]+$/m.test(input)) changes.push('Trimmed trailing whitespace');
    }

    await logToolUsage('markdown_format', 'format', { changes: changes.length }, userId, null, 'completed', Date.now() - start);
    return { success: true, output, formatted: output !== input, changes, stats: {
      linesBefore: input.split('\n').length,
      linesAfter: output.split('\n').length,
    }};
  } catch (error) {
    return { success: false, error: error.message };
  }
}

// ─── CONTENT & MARKDOWN (3 BONUS) ───

export async function markdownMerge(files = [], options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!files || files.length === 0) return { success: false, error: 'At least one markdown input required' };

    const separator = options.separator || '\n\n---\n\n';
    const addTitles = options.addTitles !== false;
    const parts = [];

    for (let i = 0; i < files.length; i++) {
      const f = files[i];
      const content = typeof f === 'string' ? f : (f.content || '');
      const title = typeof f === 'object' && f.title ? f.title : null;

      let section = '';
      if (addTitles && title) {
        section += `# ${title}\n\n`;
      }
      section += content.trim();
      parts.push(section);
    }

    const merged = parts.join(separator);
    const stats = {
      inputFiles: files.length,
      outputLines: merged.split('\n').length,
      outputChars: merged.length,
      headings: (merged.match(/^#{1,6}\s/gm) || []).length,
    };

    await logToolUsage('markdown_merge', 'merge', { files: files.length }, userId, null, 'completed', Date.now() - start);
    return { success: true, output: merged, stats };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function markdownExtract(input, action = 'headings', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Markdown input required' };

    let result;
    switch (action) {
      case 'headings': {
        const headings = [];
        const lines = input.split('\n');
        for (const line of lines) {
          const match = line.match(/^(#{1,6})\s+(.+)$/);
          if (match) headings.push({ level: match[1].length, text: match[2].trim() });
        }
        result = { headings, count: headings.length };
        break;
      }
      case 'links': {
        const links = [];
        const linkRegex = /\[([^\]]*)\]\(([^)]+)\)/g;
        let m;
        while ((m = linkRegex.exec(input)) !== null) {
          links.push({ text: m[1], url: m[2] });
        }
        result = { links, count: links.length };
        break;
      }
      case 'images': {
        const images = [];
        const imgRegex = /!\[([^\]]*)\]\(([^)]+)\)/g;
        let m;
        while ((m = imgRegex.exec(input)) !== null) {
          images.push({ alt: m[1], src: m[2] });
        }
        result = { images, count: images.length };
        break;
      }
      case 'code_blocks': {
        const blocks = [];
        const codeRegex = /```(\w*)\n([\s\S]*?)```/g;
        let m;
        while ((m = codeRegex.exec(input)) !== null) {
          blocks.push({ language: m[1] || 'plain', content: m[2].trim(), lines: m[2].trim().split('\n').length });
        }
        result = { code_blocks: blocks, count: blocks.length };
        break;
      }
      case 'frontmatter': {
        const fmMatch = input.match(/^---\n([\s\S]*?)\n---/);
        if (fmMatch) {
          const pairs = {};
          fmMatch[1].split('\n').forEach(line => {
            const [key, ...vals] = line.split(':');
            if (key) pairs[key.trim()] = vals.join(':').trim();
          });
          result = { frontmatter: pairs, raw: fmMatch[1] };
        } else {
          result = { frontmatter: null, message: 'No frontmatter found' };
        }
        break;
      }
      case 'tables': {
        const tables = [];
        const tableRegex = /(\|.+\|)\n(\|[-: ]+\|)\n((?:\|.+\|\n?)+)/g;
        let m;
        while ((m = tableRegex.exec(input)) !== null) {
          const headers = m[1].split('|').filter(c => c.trim()).map(c => c.trim());
          const rows = m[3].trim().split('\n').map(row =>
            row.split('|').filter(c => c.trim()).map(c => c.trim())
          );
          tables.push({ headers, rows, rowCount: rows.length });
        }
        result = { tables, count: tables.length };
        break;
      }
      case 'todos': {
        const todos = [];
        const todoRegex = /^[-*+]\s+\[([ xX])\]\s+(.+)$/gm;
        let m;
        while ((m = todoRegex.exec(input)) !== null) {
          todos.push({ text: m[2], completed: m[1] !== ' ' });
        }
        result = { todos, count: todos.length, completed: todos.filter(t => t.completed).length };
        break;
      }
      default:
        return { success: false, error: `Unknown extract action: ${action}. Available: headings, links, images, code_blocks, frontmatter, tables, todos` };
    }

    await logToolUsage('markdown_extract', action, { items: result.count || 0 }, userId, null, 'completed', Date.now() - start);
    return { success: true, action, ...result };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function markdownSlides(input, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Markdown input required' };

    const separator = options.separator || /^---$/m;
    const format = options.format || 'reveal';

    // Split into slides by --- or by top-level headings
    let rawSlides;
    if (typeof separator === 'string' && separator === 'headings') {
      rawSlides = input.split(/(?=^# )/m).filter(s => s.trim());
    } else {
      rawSlides = input.split(/\n---\n/).filter(s => s.trim());
    }

    const slides = rawSlides.map((content, i) => {
      const titleMatch = content.match(/^#{1,2}\s+(.+)$/m);
      return {
        index: i + 1,
        title: titleMatch ? titleMatch[1].trim() : `Slide ${i + 1}`,
        content: content.trim(),
        hasCode: /```/.test(content),
        hasImage: /!\[/.test(content),
        wordCount: content.split(/\s+/).length,
      };
    });

    let output;
    if (format === 'reveal') {
      const slideSections = slides.map(s =>
        `<section>\n${s.content
          .replace(/^# (.+)$/gm, '<h1>$1</h1>')
          .replace(/^## (.+)$/gm, '<h2>$1</h2>')
          .replace(/^### (.+)$/gm, '<h3>$1</h3>')
          .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
          .replace(/\*(.+?)\*/g, '<em>$1</em>')
          .replace(/^[-*+]\s+(.+)$/gm, '<li>$1</li>')
        }\n</section>`
      ).join('\n');
      output = `<!DOCTYPE html>
<html><head>
<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/reveal.js@4/dist/reveal.css">
<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/reveal.js@4/dist/theme/white.css">
</head><body>
<div class="reveal"><div class="slides">
${slideSections}
</div></div>
<script src="https://cdn.jsdelivr.net/npm/reveal.js@4/dist/reveal.js"><\/script>
<script>Reveal.initialize();<\/script>
</body></html>`;
    } else {
      output = slides.map(s => `--- slide ${s.index}: ${s.title} ---\n${s.content}`).join('\n\n');
    }

    await logToolUsage('markdown_slides', format, { slides: slides.length }, userId, null, 'completed', Date.now() - start);
    return { success: true, slides, slideCount: slides.length, output, format };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

