export async function analyticsExport(format = 'json', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    const hours = options.hours || 24;
    const since = new Date(Date.now() - hours * 60 * 60 * 1000);
    const limit = Math.min(options.limit || 500, 2000);

    const where = { timestamp: { gte: since } };
    if (options.eventFilter) {
      where.eventName = { contains: options.eventFilter, mode: 'insensitive' };
    }

    const events = await prisma.analyticsEvent.findMany({
      where,
      orderBy: { timestamp: 'desc' },
      take: limit,
      select: { id: true, eventName: true, userId: true, eventData: true, timestamp: true },
    });

    let output;
    if (format === 'csv') {
      const header = 'id,eventName,userId,timestamp';
      const rows = events.map(e => `${e.id},${e.eventName},${e.userId || ''},${e.timestamp.toISOString()}`);
      output = [header, ...rows].join('\n');
    } else {
      output = events;
    }

    await logToolUsage('analytics_export', format, { hours, count: events.length }, userId, null, 'completed', Date.now() - start);
    return { success: true, format, rowCount: events.length, hours, data: output };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function logAggregate(input, options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!input) return { success: false, error: 'Log content required' };

    const lines = input.split('\n').filter(Boolean);
    const groupBy = options.groupBy || 'severity';
    const topN = options.topN || 10;
    const buckets = {};

    for (const line of lines) {
      let key;
      if (groupBy === 'severity') {
        if (/\b(ERROR|FATAL|CRITICAL)\b/i.test(line)) key = 'error';
        else if (/\b(WARN|WARNING)\b/i.test(line)) key = 'warning';
        else if (/\b(INFO)\b/i.test(line)) key = 'info';
        else if (/\b(DEBUG|TRACE)\b/i.test(line)) key = 'debug';
        else key = 'other';
      } else if (groupBy === 'hour') {
        const match = line.match(/(\d{4}-\d{2}-\d{2}[T ]\d{2})/);
        key = match ? match[1] + ':00' : 'unknown';
      } else if (groupBy === 'pattern') {
        const match = line.match(/\b([A-Z][a-z]+(?:Error|Exception|Warning|Failure))\b/);
        key = match ? match[1] : 'general';
      } else if (groupBy === 'source') {
        const match = line.match(/\[([^\]]+)\]/);
        key = match ? match[1] : 'unknown';
      } else {
        key = 'all';
      }
      buckets[key] = (buckets[key] || 0) + 1;
    }

    const sorted = Object.entries(buckets)
      .sort((a, b) => b[1] - a[1])
      .slice(0, topN)
      .map(([key, count]) => ({ key, count, percent: ((count / lines.length) * 100).toFixed(1) + '%' }));

    await logToolUsage('log_aggregate', groupBy, { totalLines: lines.length }, userId, null, 'completed', Date.now() - start);
    return {
      success: true,
      groupBy,
      totalLines: lines.length,
      bucketCount: Object.keys(buckets).length,
      topEntries: sorted,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function metricsCollect(action = 'system', options = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (action === 'system' || action === 'snapshot') {
      const mem = process.memoryUsage();
      const cpus = (await import('os')).default.cpus();
      const loadAvg = (await import('os')).default.loadavg();
      const uptimeSec = process.uptime();

      const metrics = {
        memory: {
          heapUsedMB: (mem.heapUsed / 1024 / 1024).toFixed(1),
          heapTotalMB: (mem.heapTotal / 1024 / 1024).toFixed(1),
          rssMB: (mem.rss / 1024 / 1024).toFixed(1),
          externalMB: (mem.external / 1024 / 1024).toFixed(1),
        },
        cpu: {
          cores: cpus.length,
          model: cpus[0]?.model || 'unknown',
          loadAverage: { '1m': loadAvg[0]?.toFixed(2), '5m': loadAvg[1]?.toFixed(2), '15m': loadAvg[2]?.toFixed(2) },
        },
        uptime: {
          seconds: Math.floor(uptimeSec),
          formatted: `${Math.floor(uptimeSec / 3600)}h ${Math.floor((uptimeSec % 3600) / 60)}m ${Math.floor(uptimeSec % 60)}s`,
        },
        node: { version: process.version, platform: process.platform, arch: process.arch },
        timestamp: new Date().toISOString(),
      };

      await logToolUsage('metrics_collect', action, {}, userId, null, 'completed', Date.now() - start);
      return { success: true, action, metrics };
    } else if (action === 'custom') {
      if (!options.name) return { success: false, error: 'Metric name required for custom action' };
      const metric = {
        name: options.name,
        value: options.value ?? 1,
        tags: options.tags || {},
        timestamp: new Date().toISOString(),
      };

      await prisma.analyticsEvent.create({
        data: {
          visitorId: `metric_${userId}`,
          sessionId: `ms_${Date.now()}`,
          userId: userId || undefined,
          eventName: `metric:${options.name}`,
          eventData: metric,
          timestamp: new Date(),
        },
      });

      await logToolUsage('metrics_collect', 'custom', { name: options.name }, userId, null, 'completed', Date.now() - start);
      return { success: true, action: 'custom', stored: true, metric };
    }

    return { success: false, error: `Unknown action: ${action}` };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

// ─── WORKFLOW & AUTOMATION (8 NEW) — Redis-backed via cache ───

const WF_TTL = 86400; // 24 hours
function wfKey(userId) { return `workflow:store:${userId}`; }
function wfHistKey(userId) { return `workflow:history:${userId}`; }
function wfSchedKey(userId) { return `workflow:schedules:${userId}`; }
function wfTemplKey() { return `workflow:templates`; }

async function getWfStore(userId) {
  try { return (await cache.get(wfKey(userId))) || {}; } catch { return {}; }
}
async function setWfStore(userId, data) {
  try { await cache.set(wfKey(userId), data, WF_TTL); } catch { /* silent */ }
}
async function getWfHistory(userId) {
  try { return (await cache.get(wfHistKey(userId))) || []; } catch { return []; }
}
async function setWfHistory(userId, data) {
  try { await cache.set(wfHistKey(userId), data, WF_TTL); } catch { /* silent */ }
}

export async function workflowCreate(name, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!name) return { success: false, error: 'Workflow name is required' };

    const workflowId = `wf_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const steps = (params.steps || []).map((s, i) => ({
      index: i,
      name: s.name || `Step ${i + 1}`,
      tool: s.tool || 'unknown',
      params: s.params || {},
      onError: s.onError || 'stop',
      condition: s.condition || null,
      parallelGroup: s.parallel_group || s.parallelGroup || null,
      dependsOn: s.dependsOn || [],
      status: 'pending',
    }));

    const workflow = {
      id: workflowId,
      name,
      description: params.description || '',
      tags: params.tags || [],
      steps,
      status: 'created',
      currentStep: -1,
      checkpoints: {},
      results: [],
      variables: {},
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    const store = await getWfStore(userId);
    store[workflowId] = workflow;
    await setWfStore(userId, store);

    await logToolUsage('workflow_create', name, { steps: steps.length }, userId, null, 'completed', Date.now() - start);
    return {
      success: true,
      workflowId,
      name,
      stepCount: steps.length,
      status: 'created',
      message: `Workflow "${name}" created with ${steps.length} step(s). ID: ${workflowId}`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function workflowExecute(workflowId, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!workflowId) return { success: false, error: 'Workflow ID required' };

    const store = await getWfStore(userId);
    const wf = store[workflowId];
    if (!wf) return { success: false, error: `Workflow not found: ${workflowId}` };
    if (wf.steps.length === 0) return { success: false, error: 'Workflow has no steps' };

    const dryRun = params.dryRun || false;
    const startStep = params.startStep || 0;
    const variables = { ...wf.variables, ...(params.variables || {}) };

    if (dryRun) {
      const plan = wf.steps.slice(startStep).map(s => ({
        index: s.index,
        name: s.name,
        tool: s.tool,
        hasCondition: !!s.condition,
        parallelGroup: s.parallelGroup,
      }));
      return { success: true, workflowId, dryRun: true, executionPlan: plan, totalSteps: plan.length, message: 'Dry run — no steps executed' };
    }

    wf.status = 'running';
    wf.currentStep = startStep;
    wf.variables = variables;
    wf.startedAt = new Date().toISOString();
    wf.updatedAt = new Date().toISOString();

    // Track execution in history
    const execId = `exec_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
    wf.currentExecutionId = execId;
    await setWfStore(userId, store);

    const history = await getWfHistory(userId);
    history.unshift({
      executionId: execId,
      workflowId,
      workflowName: wf.name,
      status: 'running',
      startedAt: wf.startedAt,
      startStep,
      totalSteps: wf.steps.length,
      stepResults: [],
    });
    if (history.length > 100) history.length = 100;
    await setWfHistory(userId, history);

    const nextStep = wf.steps[startStep];
    await logToolUsage('workflow_execute', workflowId, { dryRun, startStep }, userId, null, 'completed', Date.now() - start);
    return {
      success: true,
      workflowId,
      executionId: execId,
      status: 'running',
      totalSteps: wf.steps.length,
      currentStep: startStep,
      nextTool: nextStep?.tool,
      nextParams: nextStep?.params,
      variables,
      message: `Workflow "${wf.name}" started at step ${startStep}. Execute: ${nextStep?.name} (tool: ${nextStep?.tool})`,
      instruction: 'Call nextTool with nextParams, then advance workflow.',
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function workflowSchedule(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!action) return { success: false, error: 'Action required' };

    let schedules;
    try { schedules = (await cache.get(wfSchedKey(userId))) || []; } catch { schedules = []; }

    switch (action) {
      case 'create': {
        if (!params.workflowId) return { success: false, error: 'workflowId required for schedule creation' };
        const scheduleId = `sched_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
        const schedule = {
          id: scheduleId,
          workflowId: params.workflowId,
          type: params.cron ? 'cron' : params.event ? 'event' : params.runAt ? 'one-time' : 'manual',
          cron: params.cron || null,
          event: params.event || null,
          runAt: params.runAt || null,
          status: 'active',
          lastRun: null,
          nextRun: params.runAt || (params.cron ? 'next cron tick' : null),
          runCount: 0,
          createdAt: new Date().toISOString(),
        };
        schedules.push(schedule);
        await cache.set(wfSchedKey(userId), schedules, WF_TTL);
        await logToolUsage('workflow_schedule', action, { scheduleId, type: schedule.type }, userId, null, 'completed', Date.now() - start);
        return { success: true, scheduleId, ...schedule, message: `Schedule "${scheduleId}" created (${schedule.type}) for workflow ${params.workflowId}` };
      }
      case 'list': {
        const filtered = params.workflowId ? schedules.filter(s => s.workflowId === params.workflowId) : schedules;
        return { success: true, schedules: filtered, total: filtered.length, message: `${filtered.length} schedule(s) found` };
      }
      case 'delete': {
        if (!params.scheduleId) return { success: false, error: 'scheduleId required' };
        const idx = schedules.findIndex(s => s.id === params.scheduleId);
        if (idx === -1) return { success: false, error: `Schedule not found: ${params.scheduleId}` };
        const removed = schedules.splice(idx, 1)[0];
        await cache.set(wfSchedKey(userId), schedules, WF_TTL);
        return { success: true, deleted: removed.id, message: `Schedule "${removed.id}" deleted` };
      }
      case 'pause': {
        const sched = schedules.find(s => s.id === params.scheduleId);
        if (!sched) return { success: false, error: `Schedule not found: ${params.scheduleId}` };
        sched.status = 'paused';
        await cache.set(wfSchedKey(userId), schedules, WF_TTL);
        return { success: true, scheduleId: sched.id, status: 'paused', message: `Schedule "${sched.id}" paused` };
      }
      case 'resume': {
        const sched = schedules.find(s => s.id === params.scheduleId);
        if (!sched) return { success: false, error: `Schedule not found: ${params.scheduleId}` };
        sched.status = 'active';
        await cache.set(wfSchedKey(userId), schedules, WF_TTL);
        return { success: true, scheduleId: sched.id, status: 'active', message: `Schedule "${sched.id}" resumed` };
      }
      default:
        return { success: false, error: `Unknown action: ${action}. Valid: create, list, delete, pause, resume` };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function workflowVisualize(workflowId, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!workflowId) return { success: false, error: 'Workflow ID required' };

    const store = await getWfStore(userId);
    const wf = store[workflowId];
    if (!wf) return { success: false, error: `Workflow not found: ${workflowId}` };

    const format = params.format || 'mermaid';
    const steps = wf.steps;

    if (format === 'mermaid') {
      let mermaid = `graph TD\n  START([Start: ${wf.name}])`;
      const groups = {};

      for (const step of steps) {
        const nodeId = `S${step.index}`;
        const label = `${step.name}\\n(${step.tool})`;
        const statusIcon = step.status === 'completed' ? '✅' : step.status === 'failed' ? '❌' : step.status === 'running' ? '🔄' : '⏳';
        mermaid += `\n  ${nodeId}["${statusIcon} ${label}"]`;

        if (step.parallelGroup) {
          if (!groups[step.parallelGroup]) groups[step.parallelGroup] = [];
          groups[step.parallelGroup].push(nodeId);
        }
      }

      // Edges
      if (steps.length > 0) mermaid += `\n  START --> S0`;
      for (let i = 0; i < steps.length - 1; i++) {
        const s = steps[i];
        if (s.dependsOn && s.dependsOn.length > 0) {
          for (const dep of s.dependsOn) mermaid += `\n  S${dep} --> S${i}`;
        }
        if (!s.parallelGroup || s.parallelGroup !== steps[i + 1]?.parallelGroup) {
          mermaid += `\n  S${i} --> S${i + 1}`;
        }
        if (s.condition) mermaid += `\n  S${i} -.->|"${s.condition}"| S${i + 1}`;
      }
      mermaid += `\n  S${steps.length - 1} --> END([End])`;

      // Parallel subgraphs
      for (const [group, nodes] of Object.entries(groups)) {
        mermaid += `\n  subgraph ${group}[Parallel: ${group}]`;
        for (const n of nodes) mermaid += `\n    ${n}`;
        mermaid += `\n  end`;
      }

      await logToolUsage('workflow_visualize', workflowId, { format }, userId, null, 'completed', Date.now() - start);
      return { success: true, workflowId, format: 'mermaid', diagram: mermaid, stepCount: steps.length };
    } else if (format === 'ascii') {
      let ascii = `=== ${wf.name} (${wf.status}) ===\n`;
      for (const step of steps) {
        const icon = step.status === 'completed' ? '[✓]' : step.status === 'failed' ? '[✗]' : step.status === 'running' ? '[→]' : '[ ]';
        const pg = step.parallelGroup ? ` ‖${step.parallelGroup}` : '';
        const cond = step.condition ? ` if(${step.condition})` : '';
        ascii += `  ${icon} ${step.index}: ${step.name} → ${step.tool}${pg}${cond}\n`;
      }
      return { success: true, workflowId, format: 'ascii', diagram: ascii, stepCount: steps.length };
    } else if (format === 'json') {
      return { success: true, workflowId, format: 'json', graph: { nodes: steps.map(s => ({ id: s.index, label: s.name, tool: s.tool, status: s.status, group: s.parallelGroup })), edges: steps.slice(1).map((s, i) => ({ from: i, to: i + 1 })) } };
    }

    return { success: false, error: `Unknown format: ${format}` };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

export async function workflowOptimize(workflowId, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    if (!workflowId) return { success: false, error: 'Workflow ID required' };

    const store = await getWfStore(userId);
    const wf = store[workflowId];
    if (!wf) return { success: false, error: `Workflow not found: ${workflowId}` };

    const focus = params.focus || 'all';
    const suggestions = [];
    const steps = wf.steps;

    // Detect parallelization opportunities
    const independent = [];
    for (let i = 0; i < steps.length; i++) {
      if (!steps[i].dependsOn?.length && !steps[i].parallelGroup) {
        independent.push(steps[i]);
      }
    }
    if (independent.length >= 2 && (focus === 'speed' || focus === 'all')) {
      suggestions.push({
        type: 'parallelization',
        severity: 'high',
        message: `${independent.length} steps have no dependencies — they could run in parallel, reducing total time by up to ${Math.round((1 - 1 / independent.length) * 100)}%`,
        steps: independent.map(s => s.name),
      });
    }

    // Detect redundant steps (same tool + same params)
    const seen = new Map();
    for (const step of steps) {
      const key = `${step.tool}:${JSON.stringify(step.params)}`;
      if (seen.has(key)) {
        suggestions.push({
          type: 'redundancy',
          severity: 'medium',
          message: `Step "${step.name}" duplicates "${seen.get(key)}" — same tool and params`,
          steps: [seen.get(key), step.name],
        });
      }
      seen.set(key, step.name);
    }

    // Detect steps with no error handling
    const noErrorHandling = steps.filter(s => s.onError === 'stop');
    if (noErrorHandling.length > steps.length / 2 && (focus === 'reliability' || focus === 'all')) {
      suggestions.push({
        type: 'reliability',
        severity: 'medium',
        message: `${noErrorHandling.length}/${steps.length} steps use onError="stop" — consider "skip" or "retry" for non-critical steps`,
        steps: noErrorHandling.map(s => s.name),
      });
    }

    // Detect long chains that could be batched
    if (steps.length > 5 && (focus === 'speed' || focus === 'all')) {
      const toolGroups = {};
      for (const s of steps) { toolGroups[s.tool] = (toolGroups[s.tool] || 0) + 1; }
      for (const [tool, count] of Object.entries(toolGroups)) {
        if (count >= 3) {
          suggestions.push({
            type: 'batching',
            severity: 'low',
            message: `Tool "${tool}" is used ${count} times — consider batch processing if supported`,
          });
        }
      }
    }

    await logToolUsage('workflow_optimize', workflowId, { focus, suggestionCount: suggestions.length }, userId, null, 'completed', Date.now() - start);
    return {
      success: true,
      workflowId,
      workflowName: wf.name,
      focus,
      totalSteps: steps.length,
      suggestions,
      score: suggestions.length === 0 ? 'optimal' : suggestions.some(s => s.severity === 'high') ? 'needs_improvement' : 'good',
      message: `${suggestions.length} optimization suggestion(s) for "${wf.name}"`,
    };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

