// ─── Finance & Accounting ───

export async function invoiceGenerate(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    const id = params.invoiceId || `INV-${Date.now()}`;
    let result;
    switch (action) {
      case 'create': {
        const items = (params.items || []).map(i => ({
          description: i.description || 'Item',
          quantity: i.quantity || 1,
          unitPrice: i.unitPrice || 0,
          total: (i.quantity || 1) * (i.unitPrice || 0),
        }));
        const subtotal = items.reduce((s, i) => s + i.total, 0);
        const taxAmount = subtotal * ((params.taxRate || 0) / 100);
        const discountAmount = subtotal * ((params.discount || 0) / 100);
        const total = subtotal + taxAmount - discountAmount;
        const invoice = {
          invoiceId: id, client: params.client, items, subtotal,
          taxRate: params.taxRate || 0, taxAmount, discount: params.discount || 0,
          discountAmount, total, currency: params.currency || 'USD',
          dueDate: params.dueDate, notes: params.notes, status: 'draft',
          createdAt: new Date().toISOString(),
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'invoice_created', eventData: invoice, userId, source: 'tool' } });
        result = { success: true, invoice };
        break;
      }
      case 'list': {
        const invoices = await prisma.analyticsEvent.findMany({ where: { eventName: 'invoice_created', userId }, orderBy: { createdAt: 'desc' }, take: 50 });
        result = { success: true, invoices: invoices.map(i => i.eventData), count: invoices.length };
        break;
      }
      case 'get': {
        const inv = await prisma.analyticsEvent.findFirst({ where: { eventName: 'invoice_created', userId, eventData: { path: ['invoiceId'], equals: id } } });
        result = inv ? { success: true, invoice: inv.eventData } : { success: false, error: 'Invoice not found' };
        break;
      }
      default:
        result = { success: true, action, invoiceId: id, message: `Invoice ${action} completed` };
    }
    await logToolUsage('invoice_generate', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

export async function expenseTrack(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'add': {
        const expense = {
          expenseId: `EXP-${Date.now()}`, amount: params.amount || 0,
          category: params.category || 'other', description: params.description || '',
          date: params.date || new Date().toISOString().split('T')[0],
          vendor: params.vendor || '', status: 'pending',
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'expense_added', eventData: expense, userId, source: 'tool' } });
        result = { success: true, expense };
        break;
      }
      case 'list': {
        const expenses = await prisma.analyticsEvent.findMany({ where: { eventName: 'expense_added', userId }, orderBy: { createdAt: 'desc' }, take: 100 });
        result = { success: true, expenses: expenses.map(e => e.eventData), count: expenses.length };
        break;
      }
      case 'report': {
        const all = await prisma.analyticsEvent.findMany({ where: { eventName: 'expense_added', userId } });
        const byCat = {};
        let total = 0;
        all.forEach(e => {
          const d = e.eventData || {};
          byCat[d.category || 'other'] = (byCat[d.category || 'other'] || 0) + (d.amount || 0);
          total += d.amount || 0;
        });
        result = { success: true, total, byCategory: byCat, count: all.length, period: params.period || 'all' };
        break;
      }
      default:
        result = { success: true, action, message: `Expense ${action} completed` };
    }
    await logToolUsage('expense_track', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

export async function budgetPlan(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'create': {
        const budget = {
          budgetId: `BUD-${Date.now()}`, name: params.name || 'Budget',
          totalAmount: params.totalAmount || 0, categories: params.categories || {},
          period: params.period || 'monthly', status: 'active',
          spent: 0, remaining: params.totalAmount || 0,
          createdAt: new Date().toISOString(),
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'budget_created', eventData: budget, userId, source: 'tool' } });
        result = { success: true, budget };
        break;
      }
      case 'list': {
        const budgets = await prisma.analyticsEvent.findMany({ where: { eventName: 'budget_created', userId }, orderBy: { createdAt: 'desc' }, take: 50 });
        result = { success: true, budgets: budgets.map(b => b.eventData), count: budgets.length };
        break;
      }
      case 'variance': {
        const expenses = await prisma.analyticsEvent.findMany({ where: { eventName: 'expense_added', userId } });
        const budgets = await prisma.analyticsEvent.findMany({ where: { eventName: 'budget_created', userId }, take: 1, orderBy: { createdAt: 'desc' } });
        const budget = budgets[0]?.eventData || {};
        const spent = {};
        expenses.forEach(e => {
          const d = e.eventData || {};
          spent[d.category || 'other'] = (spent[d.category || 'other'] || 0) + (d.amount || 0);
        });
        const variance = {};
        for (const [cat, allocated] of Object.entries(budget.categories || {})) {
          variance[cat] = { allocated, spent: spent[cat] || 0, variance: allocated - (spent[cat] || 0) };
        }
        result = { success: true, variance, budgetName: budget.name };
        break;
      }
      default:
        result = { success: true, action, message: `Budget ${action} completed` };
    }
    await logToolUsage('budget_plan', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

export async function financialReport(type, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    const invoices = await prisma.analyticsEvent.findMany({ where: { eventName: 'invoice_created', userId } });
    const expenses = await prisma.analyticsEvent.findMany({ where: { eventName: 'expense_added', userId } });
    const totalRevenue = invoices.reduce((s, i) => s + ((i.eventData || {}).total || 0), 0);
    const totalExpenses = expenses.reduce((s, e) => s + ((e.eventData || {}).amount || 0), 0);
    let report;
    switch (type) {
      case 'profit_loss':
        report = { type: 'Profit & Loss', revenue: totalRevenue, expenses: totalExpenses, netIncome: totalRevenue - totalExpenses, margin: totalRevenue ? ((totalRevenue - totalExpenses) / totalRevenue * 100).toFixed(1) + '%' : '0%' };
        break;
      case 'cash_flow':
        report = { type: 'Cash Flow', inflows: totalRevenue, outflows: totalExpenses, netCashFlow: totalRevenue - totalExpenses };
        break;
      case 'expense_summary': {
        const byCat = {};
        expenses.forEach(e => { const d = e.eventData || {}; byCat[d.category || 'other'] = (byCat[d.category || 'other'] || 0) + (d.amount || 0); });
        report = { type: 'Expense Summary', total: totalExpenses, byCategory: byCat, count: expenses.length };
        break;
      }
      default:
        report = { type, revenue: totalRevenue, expenses: totalExpenses, netIncome: totalRevenue - totalExpenses };
    }
    report.period = { start: params.startDate || 'all', end: params.endDate || 'all' };
    report.currency = params.currency || 'USD';
    report.generatedAt = new Date().toISOString();
    await prisma.analyticsEvent.create({ data: { eventName: 'financial_report', eventData: report, userId, source: 'tool' } });
    await logToolUsage('financial_report', type, params, userId, null, 'completed', Date.now() - start);
    return { success: true, report };
  } catch (error) { return { success: false, error: error.message }; }
}

export async function taxCalculate(type, amount, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    const jurisdiction = params.jurisdiction || 'US';
    const deductions = params.deductions || 0;
    const taxable = Math.max(0, amount - deductions);
    let result;
    switch (type) {
      case 'income': {
        // Simplified progressive brackets (US-style)
        const brackets = [
          { limit: 11000, rate: 0.10 }, { limit: 44725, rate: 0.12 },
          { limit: 95375, rate: 0.22 }, { limit: 182100, rate: 0.24 },
          { limit: 231250, rate: 0.32 }, { limit: 578125, rate: 0.35 },
          { limit: Infinity, rate: 0.37 },
        ];
        let tax = 0, prev = 0;
        for (const b of brackets) {
          if (taxable <= prev) break;
          const chunk = Math.min(taxable, b.limit) - prev;
          tax += chunk * b.rate;
          prev = b.limit;
        }
        result = { type: 'income', grossIncome: amount, deductions, taxableIncome: taxable, estimatedTax: Math.round(tax * 100) / 100, effectiveRate: taxable ? (tax / taxable * 100).toFixed(1) + '%' : '0%', jurisdiction };
        break;
      }
      case 'sales': case 'vat': {
        const rate = type === 'vat' ? 0.20 : 0.0825;
        const tax = amount * rate;
        result = { type, amount, rate: (rate * 100) + '%', taxAmount: Math.round(tax * 100) / 100, total: Math.round((amount + tax) * 100) / 100, jurisdiction };
        break;
      }
      case 'corporate': {
        const rate = 0.21;
        const tax = taxable * rate;
        result = { type: 'corporate', revenue: amount, deductions, taxable, rate: '21%', tax: Math.round(tax * 100) / 100, jurisdiction };
        break;
      }
      default:
        result = { type, amount, taxable, message: 'Tax calculated', jurisdiction };
    }
    await logToolUsage('tax_calculate', type, { amount, jurisdiction }, userId, null, 'completed', Date.now() - start);
    return { success: true, ...result };
  } catch (error) { return { success: false, error: error.message }; }
}

export async function currencyConvert(amount, from, to, date, userId = 'default') {
  const start = Date.now();
  try {
    // Use exchangerate-api or fallback to static rates
    let rate = 1;
    const staticRates = {
      USD: 1, EUR: 0.92, GBP: 0.79, JPY: 149.5, CAD: 1.36, AUD: 1.53,
      CHF: 0.88, CNY: 7.24, INR: 83.1, MXN: 17.2, BRL: 4.97, KRW: 1330,
      SGD: 1.34, HKD: 7.82, NOK: 10.5, SEK: 10.4, DKK: 6.87, NZD: 1.63,
      ZAR: 18.7, RUB: 91.5, TRY: 30.2, THB: 35.2, MYR: 4.72, PHP: 56.1,
    };
    try {
      const resp = await fetch(`https://api.exchangerate-api.com/v4/latest/${from}`, { signal: AbortSignal.timeout(5000) });
      if (resp.ok) {
        const data = await resp.json();
        rate = data.rates?.[to] || (staticRates[to] / staticRates[from]);
      } else {
        rate = (staticRates[to] || 1) / (staticRates[from] || 1);
      }
    } catch {
      rate = (staticRates[to] || 1) / (staticRates[from] || 1);
    }
    const converted = Math.round(amount * rate * 100) / 100;
    await logToolUsage('currency_convert', 'convert', { amount, from, to }, userId, null, 'completed', Date.now() - start);
    return { success: true, amount, from, to, rate: Math.round(rate * 10000) / 10000, converted, date: date || new Date().toISOString().split('T')[0] };
  } catch (error) { return { success: false, error: error.message }; }
}

export async function paymentProcess(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'create': {
        const payment = {
          paymentId: `PAY-${Date.now()}`, amount: params.amount || 0,
          currency: params.currency || 'USD', method: params.method || 'other',
          description: params.description || '', invoiceId: params.invoiceId || null,
          status: 'completed', processedAt: new Date().toISOString(),
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'payment_processed', eventData: payment, userId, source: 'tool' } });
        result = { success: true, payment };
        break;
      }
      case 'list': {
        const payments = await prisma.analyticsEvent.findMany({ where: { eventName: 'payment_processed', userId }, orderBy: { createdAt: 'desc' }, take: 100 });
        result = { success: true, payments: payments.map(p => p.eventData), count: payments.length };
        break;
      }
      case 'reconcile': {
        const payments = await prisma.analyticsEvent.findMany({ where: { eventName: 'payment_processed', userId } });
        const invoices = await prisma.analyticsEvent.findMany({ where: { eventName: 'invoice_created', userId } });
        const totalPaid = payments.reduce((s, p) => s + ((p.eventData || {}).amount || 0), 0);
        const totalInvoiced = invoices.reduce((s, i) => s + ((i.eventData || {}).total || 0), 0);
        result = { success: true, totalPaid, totalInvoiced, difference: totalInvoiced - totalPaid, matched: Math.abs(totalInvoiced - totalPaid) < 0.01 };
        break;
      }
      default:
        result = { success: true, action, message: `Payment ${action} completed` };
    }
    await logToolUsage('payment_process', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

