export async function ganttGenerate(params = {}, userId = 'default') {
  const start = Date.now();
  try {
    // Fetch tasks from DB or use provided tasks
    let tasks = params.tasks || [];
    if (params.projectId && tasks.length === 0) {
      const dbTasks = await prisma.analyticsEvent.findMany({ where: { eventName: 'task_created', userId } });
      tasks = dbTasks.map(t => t.eventData).filter(t => !params.projectId || t.projectId === params.projectId);
    }
    const format = params.format || 'mermaid';
    let output;
    if (format === 'mermaid') {
      output = 'gantt\n  title Project Timeline\n  dateFormat YYYY-MM-DD\n';
      let section = '';
      tasks.forEach(t => {
        const name = t.name || t.title || 'Task';
        const s = t.start || t.startDate || t.createdAt?.split('T')[0] || '2026-01-01';
        const e = t.end || t.endDate || t.dueDate || '2026-01-15';
        if (t.section && t.section !== section) { output += `  section ${t.section}\n`; section = t.section; }
        output += `  ${name} :${t.status === 'done' ? 'done,' : ''} ${s}, ${e}\n`;
      });
    } else if (format === 'markdown') {
      output = '| Task | Start | End | Status |\n|---|---|---|---|\n';
      tasks.forEach(t => {
        output += `| ${t.name || t.title} | ${t.start || t.startDate || ''} | ${t.end || t.endDate || t.dueDate || ''} | ${t.status || 'active'} |\n`;
      });
    } else {
      output = tasks;
    }
    await logToolUsage('gantt_generate', 'generate', { format, taskCount: tasks.length }, userId, null, 'completed', Date.now() - start);
    return { success: true, format, taskCount: tasks.length, output };
  } catch (error) { return { success: false, error: error.message }; }
}

export async function sprintPlan(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'create': {
        const sprint = {
          sprintId: `SPR-${Date.now()}`, name: params.name || 'Sprint',
          projectId: params.projectId || '', startDate: params.startDate,
          endDate: params.endDate, capacity: params.capacity || 20,
          stories: params.stories || [], status: 'planned',
          totalPoints: (params.stories || []).reduce((s, st) => s + (st.points || 0), 0),
          createdAt: new Date().toISOString(),
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'sprint_created', eventData: sprint, userId, source: 'tool' } });
        result = { success: true, sprint };
        break;
      }
      case 'velocity': {
        const sprints = await prisma.analyticsEvent.findMany({ where: { eventName: 'sprint_created', userId }, orderBy: { createdAt: 'desc' }, take: 10 });
        const velocities = sprints.map(s => ({ name: s.eventData?.name, points: s.eventData?.totalPoints || 0 }));
        const avg = velocities.length ? velocities.reduce((s, v) => s + v.points, 0) / velocities.length : 0;
        result = { success: true, velocities, averageVelocity: Math.round(avg * 10) / 10, sprintCount: velocities.length };
        break;
      }
      case 'burndown': {
        const tasks = await prisma.analyticsEvent.findMany({ where: { eventName: 'task_created', userId }, orderBy: { createdAt: 'desc' }, take: 50 });
        const total = tasks.length;
        const done = tasks.filter(t => (t.eventData || {}).status === 'done').length;
        result = { success: true, totalTasks: total, completed: done, remaining: total - done, burnRate: total ? Math.round(done / total * 100) : 0 };
        break;
      }
      default:
        result = { success: true, action, message: `Sprint ${action} completed` };
    }
    await logToolUsage('sprint_plan', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

