export async function deadlineTrack(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'add': {
        const deadline = {
          deadlineId: `DL-${Date.now()}`, name: params.name,
          date: params.date, projectId: params.projectId || '',
          priority: params.priority || 'medium', owner: params.owner || '',
          status: 'active', createdAt: new Date().toISOString(),
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'deadline_added', eventData: deadline, userId, source: 'tool' } });
        result = { success: true, deadline };
        break;
      }
      case 'upcoming': case 'list': {
        const deadlines = await prisma.analyticsEvent.findMany({ where: { eventName: 'deadline_added', userId }, orderBy: { createdAt: 'desc' }, take: 50 });
        const now = new Date();
        const daysAhead = params.daysAhead || 30;
        const items = deadlines.map(d => d.eventData).filter(d => {
          if (action === 'list') return true;
          const date = new Date(d.date);
          return date >= now && date <= new Date(now.getTime() + daysAhead * 86400000);
        });
        result = { success: true, deadlines: items, count: items.length };
        break;
      }
      case 'overdue': {
        const deadlines = await prisma.analyticsEvent.findMany({ where: { eventName: 'deadline_added', userId } });
        const now = new Date();
        const overdue = deadlines.map(d => d.eventData).filter(d => new Date(d.date) < now && d.status === 'active');
        result = { success: true, overdue, count: overdue.length };
        break;
      }
      default:
        result = { success: true, action, message: `Deadline ${action} completed` };
    }
    await logToolUsage('deadline_track', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

