export async function resumeParse(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'parse': {
        const content = params.content || '';
        const lines = content.split('\n').filter(l => l.trim());
        const emailMatch = content.match(/[\w.-]+@[\w.-]+\.\w+/);
        const phoneMatch = content.match(/[\+]?[\d\s\-\(\)]{10,}/);
        const parsed = {
          name: lines[0] || 'Unknown',
          email: emailMatch ? emailMatch[0] : '',
          phone: phoneMatch ? phoneMatch[0].trim() : '',
          sections: [],
          skills: [],
          lineCount: lines.length,
        };
        // Extract sections
        const sectionHeaders = ['experience', 'education', 'skills', 'summary', 'objective', 'projects', 'certifications'];
        lines.forEach(line => {
          const lower = line.toLowerCase().trim();
          if (sectionHeaders.some(h => lower.includes(h))) parsed.sections.push(line.trim());
        });
        // Extract skills (common patterns)
        const skillPatterns = /(?:skills?|technologies?|proficient|experienced)\s*:?\s*(.+)/i;
        const skillMatch = content.match(skillPatterns);
        if (skillMatch) parsed.skills = skillMatch[1].split(/[,;|]/).map(s => s.trim()).filter(Boolean);
        await prisma.analyticsEvent.create({ data: { eventName: 'resume_parsed', eventData: parsed, userId, source: 'tool' } });
        result = { success: true, parsed };
        break;
      }
      case 'score': {
        const jd = params.jobDescription || '';
        const resume = params.content || '';
        const jdWords = new Set(jd.toLowerCase().split(/\W+/).filter(w => w.length > 3));
        const resumeWords = new Set(resume.toLowerCase().split(/\W+/).filter(w => w.length > 3));
        let matches = 0;
        jdWords.forEach(w => { if (resumeWords.has(w)) matches++; });
        const score = jdWords.size ? Math.round(matches / jdWords.size * 100) : 0;
        result = { success: true, score, matchedKeywords: matches, totalKeywords: jdWords.size, recommendation: score >= 70 ? 'Strong match' : score >= 40 ? 'Moderate match' : 'Weak match' };
        break;
      }
      default:
        result = { success: true, action, message: `Resume ${action} completed` };
    }
    await logToolUsage('resume_parse', action, {}, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

