export async function payrollCalculate(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'calculate': {
        const baseSalary = params.baseSalary || 0;
        const payPeriod = params.payPeriod || 'monthly';
        const divisors = { weekly: 52, biweekly: 26, semimonthly: 24, monthly: 12 };
        const periodPay = baseSalary / (divisors[payPeriod] || 12);
        const overtimePay = (params.overtimeHours || 0) * (periodPay / 160 * 1.5);
        const grossPay = periodPay + overtimePay;
        const deductions = params.deductions || {};
        const totalDeductions = Object.values(deductions).reduce((s, v) => s + (Number(v) || 0), 0);
        const federalTax = grossPay * 0.22;
        const stateTax = grossPay * 0.05;
        const fica = grossPay * 0.0765;
        const totalTax = federalTax + stateTax + fica;
        const netPay = grossPay - totalDeductions - totalTax;
        result = {
          success: true, employeeName: params.employeeName, payPeriod,
          grossPay: Math.round(grossPay * 100) / 100,
          overtime: Math.round(overtimePay * 100) / 100,
          deductions: { ...deductions, total: Math.round(totalDeductions * 100) / 100 },
          taxes: {
            federal: Math.round(federalTax * 100) / 100,
            state: Math.round(stateTax * 100) / 100,
            fica: Math.round(fica * 100) / 100,
            total: Math.round(totalTax * 100) / 100,
          },
          netPay: Math.round(netPay * 100) / 100,
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'payroll_calculated', eventData: result, userId, source: 'tool' } });
        break;
      }
      case 'history': {
        const payrolls = await prisma.analyticsEvent.findMany({ where: { eventName: 'payroll_calculated', userId }, orderBy: { createdAt: 'desc' }, take: 24 });
        result = { success: true, history: payrolls.map(p => p.eventData), count: payrolls.length };
        break;
      }
      default:
        result = { success: true, action, message: `Payroll ${action} completed` };
    }
    await logToolUsage('payroll_calculate', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

