export async function orgChart(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    let result;
    switch (action) {
      case 'create': case 'add_member': {
        const member = {
          memberId: `ORG-${Date.now()}`, name: params.name || '',
          title: params.title || '', department: params.department || '',
          reportsTo: params.reportsTo || null,
          createdAt: new Date().toISOString(),
        };
        await prisma.analyticsEvent.create({ data: { eventName: 'org_member_added', eventData: member, userId, source: 'tool' } });
        result = { success: true, member };
        break;
      }
      case 'get': case 'export': {
        const members = await prisma.analyticsEvent.findMany({ where: { eventName: 'org_member_added', userId }, orderBy: { createdAt: 'asc' } });
        const tree = members.map(m => m.eventData);
        const format = params.format || 'json';
        if (format === 'mermaid') {
          let chart = 'graph TD\n';
          tree.forEach(m => {
            if (m.reportsTo) chart += `  ${m.reportsTo.replace(/\s/g, '_')}["${m.reportsTo}"] --> ${m.name.replace(/\s/g, '_')}["${m.name}<br/>${m.title}"]\n`;
            else chart += `  ${m.name.replace(/\s/g, '_')}["${m.name}<br/>${m.title}"]\n`;
          });
          result = { success: true, format: 'mermaid', chart, memberCount: tree.length };
        } else if (format === 'tree') {
          let output = '';
          const roots = tree.filter(m => !m.reportsTo);
          const printTree = (member, indent = '') => {
            output += `${indent}${member.name} (${member.title}) - ${member.department}\n`;
            tree.filter(m => m.reportsTo === member.name).forEach(child => printTree(child, indent + '  '));
          };
          roots.forEach(r => printTree(r));
          result = { success: true, format: 'tree', chart: output, memberCount: tree.length };
        } else {
          result = { success: true, members: tree, count: tree.length };
        }
        break;
      }
      default:
        result = { success: true, action, message: `Org chart ${action} completed` };
    }
    await logToolUsage('org_chart', action, params, userId, null, 'completed', Date.now() - start);
    return result;
  } catch (error) { return { success: false, error: error.message }; }
}

