export async function seoAudit(action, params = {}, userId = 'default') {
  const start = Date.now();
  try {
    const url = params.url || '';
    let audit;
    if (url) {
      try {
        const resp = await fetch(url, { signal: AbortSignal.timeout(10000) });
        const html = await resp.text();
        const dom = new JSDOM(html);
        const doc = dom.window.document;
        audit = {
          url,
          title: doc.querySelector('title')?.textContent || 'Missing',
          metaDescription: doc.querySelector('meta[name="description"]')?.content || 'Missing',
          h1Count: doc.querySelectorAll('h1').length,
          h2Count: doc.querySelectorAll('h2').length,
          imgWithoutAlt: doc.querySelectorAll('img:not([alt])').length,
          totalImages: doc.querySelectorAll('img').length,
          internalLinks: doc.querySelectorAll('a[href^="/"]').length,
          externalLinks: doc.querySelectorAll('a[href^="http"]').length,
          hasCanonical: !!doc.querySelector('link[rel="canonical"]'),
          hasRobotsMeta: !!doc.querySelector('meta[name="robots"]'),
          hasViewport: !!doc.querySelector('meta[name="viewport"]'),
          wordCount: doc.body?.textContent?.split(/\s+/).length || 0,
        };
        // Score
        let score = 100;
        if (audit.title === 'Missing') score -= 20;
        if (audit.metaDescription === 'Missing') score -= 15;
        if (audit.h1Count === 0) score -= 15;
        if (audit.h1Count > 1) score -= 5;
        if (audit.imgWithoutAlt > 0) score -= Math.min(10, audit.imgWithoutAlt * 2);
        if (!audit.hasCanonical) score -= 5;
        if (!audit.hasViewport) score -= 10;
        audit.score = Math.max(0, score);
        audit.grade = score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 70 ? 'C' : score >= 60 ? 'D' : 'F';
      } catch {
        audit = { url, error: 'Could not fetch URL', score: 0 };
      }
    } else {
      audit = { error: 'No URL provided' };
    }
    await prisma.analyticsEvent.create({ data: { eventName: 'seo_audit', eventData: audit, userId, source: 'tool' } });
    await logToolUsage('seo_audit', action, { url }, userId, null, 'completed', Date.now() - start);
    return { success: true, audit };
  } catch (error) { return { success: false, error: error.message }; }
}

